	 ('dcfae96a-caf0-413f-b906-fe53500a940e'::uuid,'EF69LP05','Inferir e justificar, em textos multissemióticos – tirinhas, charges, memes, gifs etc. –, o efeito de humor, ironia e/ou crítica pelo uso ambíguo de palavras, expressões ou imagens ambíguas, de clichês, de recursos iconográficos, de pontuação etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b76e277b-098c-4f7b-8d13-972bab8fccdb'::uuid,'EF69LP06','Produzir e publicar notícias, fotodenúncias, fotorreportagens, reportagens, reportagens multimidiáticas, infográficos, podcasts noticiosos, entrevistas, cartas de leitor, comentários, artigos de opinião de interesse local ou global, textos de apresentação e apreciação de produção cultural (resenhas e outros), vlogs noticiosos, culturais etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('1ca9911f-b38e-407c-b310-c8a9929d2cc8'::uuid,'EF69LP07','Produzir textos em diferentes gêneros, considerando sua adequação ao contexto de produção e circulação – os enunciadores envolvidos, os objetivos, o gênero, o suporte, a circulação –, ao modo (escrito ou oral; imagem estática ou em movimento etc.), à variedade linguística e/ou semiótica apropriada a esse contexto, à construção da textualidade relacionada às propriedades textuais e do gênero.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c46f4f20-7929-4a72-9d5b-f77aaf50002a'::uuid,'EF69LP08','Revisar/editar o texto produzido – tendo em vista sua adequação ao contexto de produção, a mídia em questão, características do gênero, aspectos linguísticos, gramaticais, ortográficos e de pontuação – e a articulação da escrita com outras linguagens.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c3a3a799-8237-47af-970d-505f23266c11'::uuid,'EF69LP09','Planejar uma campanha publicitária sobre questões/problemas, temas, causas significativas para a escola e/ou comunidade, a partir de um levantamento de material sobre o tema ou evento, da definição do público-alvo, do texto ou peça a ser produzido, pelo grupo ou individualmente, dos meios de circulação, da mídia a ser utilizada e da organização da socialização dos resultados.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('65adfe43-31e1-4e09-a473-f2d962c1280e'::uuid,'EF69LP10','Produzir notícias para rádios, TV ou vídeos, podcasts noticiosos e de opinião, entrevistas, comentários, vlogs, booktrailers, documentários, dentre outros, com a formatação e diagramação (visual e sonora) adequada.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e8ed79a2-e5bc-427a-9fe8-3f71c2cfe075'::uuid,'EF69LP11','Identificar e analisar posicionamentos defendidos e refutados na escuta de interações polêmicas em entrevistas, discussões e debates (televisivo, em sala de aula, em redes sociais etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('9d049181-2ce2-4ee5-b5e4-251b53637925'::uuid,'EF69LP12','Desenvolver estratégias de planejamento, elaboração, revisão, edição, reescrita/redesign (esses três últimos quando não for situação ao vivo) e avaliação de textos orais, áudio e/ou vídeo, considerando sua adequação aos contextos em que foram produzidos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('59acc795-4cae-4c8b-a391-04e44d86a71b'::uuid,'EF69LP13','Engajar-se e contribuir com a busca de conclusões comuns relativas a problemas, temas ou questões polêmicas de interesse da turma e/ou de relevância social.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('4c12fbf2-c51f-44bb-a148-5c31ca71bf03'::uuid,'EF69LP14','Formular perguntas e decompor, com a ajuda dos colegas e dos professores, tema/questão polêmica, explicações e ou argumentos relativos ao objeto de discussão para análise mais minuciosa e buscar em fontes diversas informações ou dados que permitam analisar partes da questão e compartilhá-los com a turma.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('9f60bdcd-d95a-4b2f-bba4-5448e2c2caef'::uuid,'EF69LP15','Apresentar argumentos e contra-argumentos coerentes, respeitando os turnos de fala, na participação em discussões sobre temas controversos e/ou polêmicos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('02e02cd5-f8c0-4ce0-8002-b1fb9a0df207'::uuid,'EF69LP16','Analisar e utilizar as formas de composição dos gêneros jornalísticos da ordem do relatar, tais como notícias e reportagens.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f4675854-7a88-40c3-942f-c5810d956c2e'::uuid,'EF69LP17','Perceber e analisar os recursos estilísticos e semióticos dos gêneros jornalísticos e publicitários.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('63b4c37e-2d19-4265-9f5e-ef64bf5d37d0'::uuid,'EF69LP18','Utilizar, na escrita/reescrita de textos argumentativos, recursos linguísticos que marquem as relações de sentido entre parágrafos e enunciados do texto e operadores de conexão adequados aos tipos de argumento e à forma de composição de textos argumentativos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('49311362-df10-43a8-8694-7ddedc476bc0'::uuid,'EF69LP19','Analisar, em gêneros orais que envolvam argumentação, os efeitos de sentido de elementos típicos da modalidade falada, como a pausa, a entonação, o ritmo, a gestualidade e expressão facial, as hesitações etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5497bb12-091b-4acf-bff9-d18fc10a04b1'::uuid,'EF69LP20','Identificar, tendo em vista o contexto de produção, a forma de organização dos textos normativos e legais (lei, código, estatuto, regimento etc.), a lógica de hierarquização de seus itens e subitens e suas partes.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8fb79685-b16f-4530-ae35-634a0c253eb3'::uuid,'CEEF01LP01','Identificar as múltiplas linguagens que fazem parte do cotidiano da criança.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('011dc60f-00f2-4960-9e47-5cea40fa7078'::uuid,'EF69LP21','Posicionar-se em relação a conteúdos veiculados em práticas não institucionalizadas de participação social, sobretudo àquelas vinculadas a manifestações artísticas, produções culturais, intervenções urbanas e práticas próprias das culturas juvenis que pretendam denunciar, expor uma problemática ou "sacudir" a sensibilidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('86d9ad2a-841a-4701-b5b6-bdda0adec2d3'::uuid,'EF69LP22','Produzir, revisar e editar textos reivindicatórios ou propositivos sobre problemas que afetam a vida escolar ou da comunidade, justificando pontos de vista, reivindicações e detalhando propostas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('544c6b7d-0073-4b2b-8cc0-c9dd8128a679'::uuid,'EF69LP23','Contribuir com a escrita de textos normativos, quando houver esse tipo de demanda na escola, utilizando conhecimentos sobre a organização e recursos linguísticos desse tipo de texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('e33e7a3f-7cc5-4870-b423-bafc3a847a6c'::uuid,'EF69LP24','Discutir casos, reais ou simulações, submetidos a juízo, que envolvam (supostos) desrespeitos a artigos, do código de defesa do consumidor, do código nacional de trânsito, de regulamentações da escola, dentre outros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ceca27b3-ff31-4fa2-ba8b-01a495c9ce7f'::uuid,'EF69LP25','Posicionar-se de forma crítica e fundamentada em relação a propostas de intervenção na escola e na comunidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b11f5624-3d5a-44d8-b0d6-bb34f8bea728'::uuid,'EF69LP26','Tomar nota em discussões, debates, palestras, apresentação de propostas, reuniões, como forma de documentar o evento e apoiar a própria fala.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('406dad6a-fb22-43cb-ad26-189c0f19f4c1'::uuid,'2C1.3','H3   -   Identificar   s??labas   can??nicas   em   uma palavra.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5cca90d5-d072-49fd-8943-9e939b7653ce'::uuid,'EF69LP27','Analisar, em textos argumentativos, os mecanismos de modalização, de forma a reconhecer o modo como o enunciador se posiciona diante do que é dito.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('d01bb72c-dfb0-4014-b325-55ff3fcb2555'::uuid,'EF69LP28','Observar os mecanismos de modalização adequados aos textos jurídicos, as modalidades deônticas, que se referem ao eixo da conduta (obrigatoriedade/permissibilidade) e as modalidades apreciativas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('cab247a6-26e3-4ae1-ad93-800f4407ac63'::uuid,'EF69LP29','Refletir sobre a relação entre os contextos de produção dos gêneros de divulgação científica e os aspectos relativos à construção composicional e às marcas linguísticas características desses gêneros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('cb731d4f-b668-497e-83c1-03eea4aec7d7'::uuid,'EF69LP30','Comparar, com a ajuda do professor, conteúdos, dados e informações de diferentes fontes, levando em conta seus contextos de produção e referências, identificando coincidências, complementaridades e contradições.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e248ef90-9160-4dbd-b19a-76273159aac8'::uuid,'EF69LP31','Utilizar pistas linguísticas – tais como "em primeiro lugar", "por outro lado", "em resumo", etc. – para compreender a hierarquização das proposições.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e50aa189-d172-4a1b-9654-efd046067568'::uuid,'EF69LP32','Selecionar informações e dados relevantes de fontes diversas (impressas, digitais, orais etc.), avaliando a qualidade e a utilidade dessas fontes, e organizar, esquematicamente, com ajuda do professor, as informações necessárias.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('bc0e71fb-8082-433a-8362-ef7020e37ac5'::uuid,'EF69LP33','Articular o verbal com outras linguagens em textos multissemióticos, na organização e apresentação de informações.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ec5c360a-5cc6-4794-823b-e842cc1c1fbe'::uuid,'EF69LP34','Grifar as partes essenciais do texto, tendo em vista os objetivos de leitura, produzir marginálias, ou tomar notas em outro suporte, como estratégia de leitura.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('0fec54f0-8978-411b-86e7-1c397bf3c1b0'::uuid,'EF69LP35','Planejar textos de divulgação científica, a partir da elaboração de esquema que considere as pesquisas feitas anteriormente, de notas e sínteses de leituras ou de registros de experimentos ou de estudo de campo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('2d9ea03e-679d-470d-b055-69bcbd4c28d2'::uuid,'EF69LP36','Produzir, revisar e editar textos voltados para a divulgação do conhecimento e de dados e resultados de pesquisas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f440405f-a88b-4066-9782-fc5a3e604e38'::uuid,'EF69LP37','Produzir roteiros para elaboração de vídeos de diferentes tipos (vlog científico, vídeo-minuto, programa de rádio, podcasts) para divulgação de conhecimentos científicos e resultados de pesquisa.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5a9bc2ac-1dfc-4ade-9762-fe9c5e042fe3'::uuid,'EF69LP38','Organizar os dados e informações pesquisados em apresentações orais, tendo em vista o contexto de produção e as características do gênero.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b3eb206e-2e11-4a1e-af4f-eccbc31aa558'::uuid,'EF69LP39','Engajar-se ativamente em processos de planejamento, revisão/edição e reescrita tendo em vista as restrições temáticas, composicionais e estilísticas dos textos pretendidos e as configurações da situação de produção.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('23df700f-3cec-4711-b0f3-3b91e1ca4803'::uuid,'EF69LP40','Analisar, em textos de divulgação científica e outros gêneros, a organização e o tratamento da informação, bem como os recursos de coesão e as marcas linguísticas de impessoalização.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c4d72e15-6085-40d1-97ed-6d5ed7fa3068'::uuid,'EF69LP41','Usar adequadamente ferramentas de apoio a apresentações orais, escolhendo e usando tipos e tamanhos de fontes que permitam boa visualização, ocupando os slides de forma harmônica.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('deda5960-4246-4c42-aa4d-65bb2f6afafc'::uuid,'EI03EO09','Reconhecer e valorizar as caracter??sticas de seu corpo e de seus colegas, respeitando as diferen??as.','7af40699-ebf8-457f-9dd9-2cec2dca8cef','b3f73bca-27a7-4c86-8856-949056773776'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('f271de8a-39ff-43e1-9e20-da4a982f9b69'::uuid,'EF69LP42','Analisar a construção composicional dos textos pertencentes a gêneros relacionados à divulgação de conhecimentos: título, introdução, desenvolvimento, conclusão etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e5538017-e0c9-4476-a191-21028869da8c'::uuid,'EF01LP22','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, diagramas, entrevistas, curiosidades, dentre outros gêneros do campo investigativo, digitais ou impressos, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('910dce6d-e63a-4ee2-9a91-bb6199918a37'::uuid,'EF01LP23','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, entrevistas, curiosidades, dentre outros gêneros do campo investigativo, que possam ser repassados oralmente por meio de ferramentas digitais, em áudio ou vídeo, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('42e414b2-276d-476d-850a-52e13407fca1'::uuid,'EF69LP43','Identificar e utilizar os modos de introdução de outras vozes no texto – citação literal e sua formatação e paráfrase.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8297ee64-c3e4-47d5-835a-63521d8e8287'::uuid,'EF69LP44','Inferir a presença de valores sociais, culturais e humanos e de diferentes visões de mundo, em textos literários.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('0da89abe-ee40-41af-a8b6-461adedbb89e'::uuid,'EF69LP45','Posicionar-se criticamente em relação a textos pertencentes a gêneros como quarta-capa, programa (de teatro, dança, concerto), sinopse, resenha crítica, comentário em blog/vlog cultural etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('86453619-0815-4918-8d49-8896ec3ff63d'::uuid,'EF69LP46','Participar de práticas de compartilhamento de leitura/recepção de obras literárias/manifestações artísticas, como rodas de leitura, clubes de leitura, eventos de contação de histórias, de leituras dramáticas etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('74532f2b-bf66-4129-ba3d-7c6565f9517b'::uuid,'EF69LP47','Analisar, em textos narrativos ficcionais, as diferentes formas de composição próprias de cada gênero, os recursos coesivos e a escolha lexical típica de cada gênero.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('d2d76cf4-1fce-4272-8fb8-2f7767dba0f3'::uuid,'EF69LP48','Interpretar, em poemas, efeitos produzidos pelo uso de recursos expressivos sonoros, semânticos, gráfico-espaciais e imagens poéticas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('84c43f1c-391b-48bc-b9bb-acaa0ce82eaa'::uuid,'EF69LP49','Mostrar-se interessado e envolvido pela leitura de livros de literatura e por outras produções culturais do campo artístico-literário.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('96a01eb4-5ed6-4f73-8f16-cec51a72669f'::uuid,'EF69LP50','Elaborar texto teatral, a partir da adaptação de romances, contos, mitos, narrativas de enigma e de aventura, novelas, biografias romanceadas, crônicas, dentre outros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b7f27ad1-dc0c-44ba-b7fb-e0ab6dbc24d8'::uuid,'EF69LP51','Engajar-se ativamente nos processos de planejamento, textualização, revisão/edição e reescrita, tendo em vista as restrições temáticas, composicionais e estilísticas dos textos pretendidos e as configurações da situação de produção.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('6590470e-711b-4d11-a95b-c841b175956a'::uuid,'EF69LP52','Representar cenas ou textos dramáticos, considerando, na caracterização dos personagens, os aspectos linguísticos e paralinguísticos das falas (timbre e tom de voz, pausas e hesitações, entonação e expressividade, variedades e registros linguísticos).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5ad7a7ef-a330-4796-9da9-682ef37b1725'::uuid,'EF69LP53','Ler em voz alta textos literários diversos, bem como leituras orais capituladas, compartilhando com os colegas os sentidos produzidos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f49f0594-8da9-4417-a651-573fad02e803'::uuid,'EF69LP54','Analisar os efeitos de sentido decorrentes da interação entre os elementos linguísticos e os recursos paralinguísticos e cinésicos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('a49c948d-0b19-49ae-89f3-a3489d936ab9'::uuid,'EF69LP55','Reconhecer as variedades da língua falada, o conceito de norma-padrão e o de preconceito linguístico.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('57885e6c-fdb0-4b43-9c07-b21e5b08f5a2'::uuid,'EF69LP56','Fazer uso consciente e reflexivo de regras e normas da norma-padrão em situações de fala e escrita nas quais ela deve ser usada.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('81079e38-063a-4deb-b3fc-64b563bb4b45'::uuid,'EF67LP01','Analisar a estrutura e funcionamento dos hiperlinks em textos noticiosos publicados na Web e vislumbrar possibilidades de uma escrita hipertextual.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('3074f901-fc7c-44a6-959c-953977da46d2'::uuid,'EF67LP02','Explorar o espaço reservado ao leitor nos jornais, revistas, impressos e on-line, sites noticiosos etc., destacando a presença de valores sociais e culturais e o posicionamento ético.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7129b622-a692-4463-b47e-380aef35c0c5'::uuid,'EI03EO11','Participar de atividades coletivas, demonstrando interesse e coopera????o.','fde6213e-1efe-4eb6-b766-d4335e7caee5','35e6701a-87b9-4c46-82e5-44aa3458dd60'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('e471554e-ecb8-4616-b21a-db2391f28d58'::uuid,'EF67LP03','Comparar informações sobre um mesmo fato veiculadas em diferentes mídias e concluir sobre qual é mais confiável e por quê.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('0c123e79-e2ef-42e0-a63e-69d9ab07069e'::uuid,'EF67LP04','Distinguir, em segmentos descontínuos de textos, fato da opinião enunciada em relação a esse fato.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('62f45f09-1fb7-4472-bb47-62c8e12046a9'::uuid,'EF67LP05','Identificar e avaliar teses/opiniões/posicionamentos explícitos e argumentos em textos argumentativos (carta de leitor, comentário, artigo de opinião etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8f684700-dc5a-4055-9d67-3369367ead0c'::uuid,'EF67LP06','Identificar os efeitos de sentido provocados pela seleção lexical, topicalização de elementos e seleção e hierarquização de informações em textos noticiosos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ea1f8d49-fcbb-45e8-81c6-ec24207ffd8c'::uuid,'EF67LP07','Identificar o uso de recursos persuasivos em textos argumentativos diversos (como a escolha lexical, o uso de adjetivos e advérbios avaliativos e construções que denotam certeza, probabilidade, dúvida etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('03cd3c9b-8beb-4a0a-8570-65703d77a05d'::uuid,'EF67LP08','Identificar os efeitos de sentido devidos à escolha de imagens estáticas, sequenciação ou sobreposição de imagens, definição de figura/fundo, ângulo, profundidade de campo, foco, tonalidade, luz, uso de cores etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('a5fe9db4-3a85-4df0-a15c-3d88b0903244'::uuid,'EF67LP09','Planejar notícia impressa e para circulação em outras mídias, tendo em vista as condições de produção, do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('16de1d2a-9dd4-4f9c-97d1-b0eb5b84c226'::uuid,'EF67LP10','Produzir notícia impressa tendo em vista características do gênero – título ou manchete com verbo no tempo presente, lide, progressão dada/nova, organização em parágrafos, citações de falas de entrevistados por meio de discurso direto e indireto etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5fb77184-2100-4544-9e66-7ecfa67f70aa'::uuid,'EF67LP11','Planejar, roteirizar e produzir podcasts noticiosos e de opinião, entrevistas, comentários, vlogs etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f9634e8a-23d7-4323-a209-47d39cc0ad66'::uuid,'EI03EO12','Interagir com o meio ambiente, explorando e valorizando a natureza e seus elementos.','f077ebd9-0588-404c-81d5-02534b92ba2f','35e6701a-87b9-4c46-82e5-44aa3458dd60'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('18e8a303-7d56-446c-91c8-307cbc07c629'::uuid,'EF67LP12','Produzir resenhas críticas, vlogs, podcasts literários, playlists comentadas de obras literárias, filmes, séries, games, dentre outros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('351e5aca-1dd6-4eab-b6fd-500628c7b4f4'::uuid,'EF67LP13','Produzir, revisar e editar textos publicitários, levando em conta o contexto de produção dado, explorando recursos multissemióticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5e028e16-c6cd-4d76-9a11-919e4fceaaad'::uuid,'EF67LP14','Definir o contexto de produção da entrevista (objetivos, o que se pretende conseguir, escolha do entrevistado, mapa de roteiro etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('72d76fee-98a2-42e2-b3bf-17bc2e1744d6'::uuid,'EF67LP15','Identificar a proibição de propagandas de produtos nocivos à saúde e a influência da propaganda no consumo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('501b01d6-2d8d-4a83-a426-8e81371ded80'::uuid,'EF67LP16','Explorar e analisar espaços de reclamação de direitos e de envio de solicitações (ouvidorias, SAC, canais de ligue-denúncia, portais de prefeituras etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e073c94a-87c5-4edf-a38f-165e1e01eced'::uuid,'EF67LP17','Analisar, a partir do contexto de produção, a forma de organização das cartas de solicitação e de reclamação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e39c29b9-1f16-4e3c-8bf3-47ccd092621d'::uuid,'EF67LP18','Identificar o objeto da reclamação e/ou da solicitação e os argumentos e explicações utilizados para sustentá-la.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8f4f9521-d0a6-4cff-8c71-7a20077ff6ee'::uuid,'EF67LP19','Realizar levantamento de questões, problemas ou demandas que afetem a vida da comunidade e posicionar-se.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('1867860b-487a-42e3-a653-aac1d3c39f56'::uuid,'EF67LP20','Realizar pesquisa, a partir de recortes e questões definidos, usando fontes indicadas e abertas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7594d8cb-d1f9-4453-a82c-01f8db2fa2e5'::uuid,'EF67LP21','Divulgar resultados de pesquisas por meio de apresentações orais, verbetes de enciclopédias colaborativas, reportagens de divulgação científica, vlogs científicos, vídeos de diferentes tipos etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('5ed2f508-079f-47dd-9dbc-6a6b1ab297e2'::uuid,'EF67LP22','Produzir resumos, a partir das notas e/ou esquemas feitos, com o uso adequado de paráfrases e citações.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7bc02558-a844-48b0-9455-e253f7c4d4e2'::uuid,'EF67LP23','Respeitar os turnos de fala, na participação em conversações e em discussões ou atividades coletivas, na sala de aula e na escola.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('29960f35-7dbd-42ac-81d4-417e94775828'::uuid,'EF67LP24','Tomar nota de aulas, apresentações orais, entrevistas (ao vivo, áudio, TV, vídeo), identificando e hierarquizando as informações principais, tendo em vista o objetivo do registro.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('472f9b1e-1417-4655-ba77-42d8fbeac7e8'::uuid,'EF67LP25','Reconhecer e utilizar os critérios de organização topológica (do geral para o específico, do específico para o geral etc.) e de organização cronológica.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5c5e7119-cdf8-4d42-98ed-404b4e5ac551'::uuid,'EF67LP26','Reconhecer a estrutura de verbetes de enciclopédias e dicionários.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('bfceedee-12ad-4975-8c2d-cbfd3477f5f9'::uuid,'EF67LP27','Analisar, entre os textos literários e entre estes e outras manifestações artísticas, referências explícitas ou implícitas a outros textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('bf9decdb-4d1b-49d7-987a-bea46590432a'::uuid,'EF67LP28','Ler, de forma autônoma, e compreender – selecionando procedimentos e estratégias de leitura adequados a diferentes objetivos – romances infanto-juvenis, contos populares, contos de terror, lendas brasileiras, indígenas e africanas, narrativas de aventuras, narrativas de enigma, mitos, crônicas, autobiografias, histórias em quadrinhos, mangás, poemas de forma livre e fixa, dentre outros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('fb28295a-8093-4183-8817-60b405243f38'::uuid,'EF67LP29','Identificar, em texto dramático, personagem, ato, cena, fala e indicações cênicas e a organização do texto: enredo, conflito, ideias principais, pontos de vista, universos de referência.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ad4fcc35-0eff-415d-a927-80b2c446ccc6'::uuid,'EF67LP30','Criar narrativas ficcionais, tais como contos populares, contos de suspense, mistério, terror, humor, narrativas de enigma, crônicas, histórias em quadrinhos, dentre outros, que explorem diferentes modos de representação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('3f405d18-6bf0-4456-a989-6e9c99783477'::uuid,'EF67LP31','Criar poemas compostos por versos livres e de forma fixa (como quadras e sonetos), utilizando recursos visuais, semânticos e sonoros, tais como cadências, ritmos e rimas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('3d20260a-e841-420c-8ed6-50f047da715a'::uuid,'EF67LP32','Escrever palavras com correção ortográfica, obedecendo às convenções da língua escrita.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5a426476-ce12-445a-924d-5d8af4288b3b'::uuid,'EF67LP33','Pontuar textos adequadamente.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('4741f6f0-4910-4a4e-bd76-3effdfb13b01'::uuid,'EF67LP34','Formar antônimos com acréscimo de prefixos que expressam noção de negação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8be7e268-9b62-4d13-aea9-2942ea17b018'::uuid,'EF67LP35','Distinguir palavras derivadas por acréscimo de afixos e palavras compostas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('2a8a85d9-d63a-4386-ae90-bceced240b1d'::uuid,'EF67LP36','Utilizar, ao produzir texto, recursos de coesão referencial (léxica e pronominal) e sequencial e outros recursos expressivos adequados ao gênero textual.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('d2b6848c-3440-45d6-8520-55d9672fc909'::uuid,'EF67LP37','Analisar, em diferentes textos, os efeitos de sentido decorrentes do uso de recursos linguístico-discursivos de prescrição, causalidade, sequenciação e outros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('55325789-0aaf-4954-b0ed-57a4ad05d912'::uuid,'EF67LP38','Analisar os efeitos de sentido do uso de figuras de linguagem, como comparação, metáfora, metonímia, personificação, hipérbole, dentre outras.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('714d85c6-48aa-441c-b787-bdbd7635b640'::uuid,'EF89LP01','Analisar os interesses que movem o campo jornalístico, os efeitos das novas tecnologias no campo e as condições que fazem da informação uma mercadoria, de forma a adotar atitude crítica frente aos textos jornalísticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('2682dec3-cc3d-42b4-aae4-604ae86513fc'::uuid,'EF89LP02','Analisar diferentes práticas (curtir, compartilhar, comentar, curar etc.) e textos pertencentes a diferentes gêneros da cultura digital (meme, gif, comentário, charge digital etc.) envolvidos no trato com a informação e opinião.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b3cba05e-710e-4426-8ffc-08020dbd322a'::uuid,'EF89LP03','Analisar textos de opinião (artigos de opinião, editoriais, cartas de leitores, comentários, posts de blog e de redes sociais, charges, memes, gifs etc.) e posicionar-se de forma crítica e fundamentada, ética e respeitosa frente a fatos e opiniões relacionados a esses textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('fca5c8fc-b7f3-4a61-abd8-23ff000824fe'::uuid,'EF89LP04','Identificar e avaliar teses/opiniões/posicionamentos explícitos e implícitos, argumentos e contra-argumentos em textos argumentativos do campo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c7b349c0-0688-4f0e-a5f2-708778718718'::uuid,'EF89LP05','Analisar o efeito de sentido produzido pelo uso, em textos, de recursos de persuasão (escolha lexical, construções gramaticais, modalizadores etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7c132394-f6c7-4261-ba2f-016478cce5f1'::uuid,'EI03EO09','Reconhecer e valorizar as caracter??sticas de seu corpo e de seus colegas, respeitando as diferen??as.','24710a67-1fbf-40b6-83fb-ef9f5bad5df1','b3f73bca-27a7-4c86-8856-949056773776'::uuid),
	 ('8b56ec2b-5dbd-4bcb-8e42-94563b31ce40'::uuid,'EF89LP06','Analisar o uso de recursos persuasivos em textos argumentativos diversos (como a escolha lexical, o uso de adjetivos e advérbios avaliativos e construções que denotam certeza, probabilidade, dúvida etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('00314512-b10f-4498-9f22-57d72d88a1e0'::uuid,'EF89LP07','Analisar, em notícias, reportagens e peças publicitárias, a distinção entre fato e opinião, e os efeitos de sentido do uso de formas verbais, modalizadores etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('6127327a-301d-4195-8e2a-0e22ed597b19'::uuid,'EF89LP08','Planejar reportagem impressa e em outras mídias (rádio ou TV/vídeo, sites), tendo em vista as condições de produção do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('bacb0b4a-497d-47a7-918b-5d41c5809cc1'::uuid,'EF89LP09','Produzir reportagem impressa, com título, linha fina (optativa), organização composicional (expositiva, interpretativa e/ou opinativa), progressão temática e uso de recursos linguísticos compatíveis com as escolhas feitas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('eb53a14b-1fc9-4066-bb6e-8b43ab772e0e'::uuid,'EF89LP10','Planejar, produzir e editar artigos de opinião, tendo em vista o contexto de produção dado, assumindo posição diante de tema polêmico, argumentando de acordo com a estrutura própria desse tipo de texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ef3e53cc-4f4d-473f-9a32-3764387d234f'::uuid,'EF89LP11','Produzir, revisar e editar peças e campanhas publicitárias, envolvendo o uso articulado e complementar de diferentes peças publicitárias.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7950c69b-cc41-49a5-bfa1-8d864509b639'::uuid,'EF89LP12','Planejar, produzir e editar textos publicitários, levando em conta o contexto de produção dado e o uso de recursos multissemióticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('964d2394-b464-4ce9-8417-79320ebee066'::uuid,'EF89LP13','Analisar, em debates, entrevistas, e outros gêneros, a polidez (estratégias de atenuação e de intensificação), o uso de operadores argumentativos e de modalizadores.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c3bc3efa-9e99-434e-b3f6-303142428023'::uuid,'EF89LP14','Analisar, em textos argumentativos e propositivos, os movimentos argumentativos de sustentação, refutação e negociação e os tipos de argumentos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('0fe34bd6-c957-419f-bea1-ceae7deb994f'::uuid,'EF89LP15','Utilizar, nos debates, operadores argumentativos que marcam a defesa de ideia e de diálogo com a tese do outro: concordância ou discordância parcial ou total, etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('89fbdc9e-64f8-4f3c-b324-faa6f14aa7f0'::uuid,'EF89LP16','Analisar a modalização realizada em textos noticiosos e argumentativos, por meio das modalidades apreciativas, viabilizadas por classes e estruturas gramaticais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('fdd35259-fa61-4024-9071-c4078c9dd94d'::uuid,'EF89LP17','Relacionar textos e documentos legais e normativos de âmbito universal, nacional, local ou escolar que envolvam a definição de direitos e deveres.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f5da9040-4d5e-4fb9-9e51-622d0a400a50'::uuid,'EF89LP18','Explorar e analisar instâncias e canais de participação disponíveis na escola, na comunidade, ou via internet.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('2f12fc1e-8e37-4cb3-bdd5-a5f786180c6d'::uuid,'EF89LP19','Analisar, no contexto de produção, a forma de organização das cartas de solicitação e de reclamação, abaixo-assinados e das propostas, considerando as marcas linguísticas e os argumentos selecionados.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('237bf7d2-e9b9-4ea7-a944-074277ae487f'::uuid,'EF89LP20','Comparar as propostas políticas e de solução de problemas, identificando o que se pretende fazer/implementar, por que (motivações, justificativas), para que (objetivos, benefícios) e como (ações, passos, etapas).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('4cbdd257-a9b9-4adc-bff4-474963e4e3a4'::uuid,'EF89LP21','Realizar enquetes e pesquisas de opinião, de forma a levantar prioridades, problemas a resolver ou proposições que possam contribuir para a melhoria da escola ou da comunidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('d1d0c356-f704-43de-afe7-c34159d67521'::uuid,'EF89LP22','Compreender e comparar as diferentes posições e interesses em jogo em uma discussão ou debate.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('69332c6e-2eac-443a-937c-a801076ccc21'::uuid,'EF89LP23','Analisar, em textos argumentativos, reivindicatórios e propositivos, os movimentos argumentativos utilizados (sustentação, refutação e negociação).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('9c3a0f66-3f6c-4d17-804f-c4d66f637c41'::uuid,'EF89LP24','Realizar pesquisa, estabelecendo o recorte das questões, usando fontes abertas e confiáveis.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('64272b66-fd09-4ca5-8cdd-09a1376b2111'::uuid,'EF89LP25','Divulgar o resultado de pesquisas por meio de apresentações orais, verbetes de enciclopédias colaborativas, reportagens de divulgação científica, vlogs científicos, vídeos de diferentes tipos etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('2ce4a84a-a1f4-4e82-9c8e-76dbb59a5e74'::uuid,'EF89LP26','Produzir resenhas, vlogs, podcasts literários e aulas, verbetes de enciclopédia, dentre outros, considerando a situação comunicativa.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e9ee492a-f5d9-4f09-aa1e-2621f0c5aad6'::uuid,'EF89LP27','Tecer considerações e formular problematizações pertinentes, em momentos oportunos, em discussões, aulas, debates, apresentações.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('9f6cdbac-abd5-44c6-91cc-e51397614cac'::uuid,'EF89LP28','Tomar nota de videoaulas, aulas digitais, apresentações multimídias, vídeos de divulgação científica, documentários e afins, identificando, em função dos objetivos, informações principais para apoio ao estudo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('da04c27e-1b8e-4b07-a14f-e1fb33166a8f'::uuid,'EF89LP29','Utilizar e perceber mecanismos de progressão temática, tais como retomadas anafóricas, catáforas, uso de organizadores textuais, de coesivos etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('2704b7f8-0c47-4191-a5f4-701931fc1ff6'::uuid,'EF89LP30','Analisar a estrutura de hipertexto e hiperlinks em textos de divulgação científica e proceder à remissão a conceitos e relações por meio de links.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ef26a9ec-a905-44db-9190-3e8044629bc4'::uuid,'EF89LP31','Analisar e utilizar modalização epistêmica, isto é, modos de indicar uma avaliação sobre o valor de verdade e as condições de verdade de uma proposição.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f67ab7ee-c34d-48df-97d5-1ca349990dae'::uuid,'EF89LP32','Analisar os efeitos de sentido decorrentes do uso de mecanismos de intertextualidade (referências, alusões, retomadas) entre os textos literários, entre esses textos literários e outras manifestações artísticas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('f250a3a8-39c4-4d94-9bf9-431890e9753a'::uuid,'EF89LP33','Ler, de forma autônoma, e compreender – selecionando procedimentos e estratégias de leitura adequados a diferentes objetivos – romances, contos contemporâneos, minicontos, fábulas contemporâneas, romances juvenis, biografias romanceadas, novelas, crônicas visuais, narrativas de ficção científica, narrativas de suspense, poemas de forma livre e fixa (como haicai), poema concreto, ciberpoema, dentre outros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e239421d-edf8-42a5-90aa-090ed9157502'::uuid,'EI03EO09','Reconhecer e valorizar as caracter??sticas de seu corpo e de seus colegas, respeitando as diferen??as.','f077ebd9-0588-404c-81d5-02534b92ba2f','b3f73bca-27a7-4c86-8856-949056773776'::uuid),
	 ('bb8f0f75-a3d2-4ff6-ac72-3c42a799a239'::uuid,'EF89LP34','Analisar a organização de texto dramático apresentado em teatro, televisão, cinema, identificando e caracterizando o cenário, o figurino e a encenação e reconhecendo os recursos linguísticos e semióticos envolvidos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('abde6b45-9186-43aa-843f-5c437019bde0'::uuid,'EF89LP35','Criar contos ou crônicas (em especial, líricas), crônicas visuais, minicontos, narrativas de aventura e de ficção científica, dentre outros, com temáticas próprias ao gênero.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e69aade4-0173-4bd2-96cb-07ec3204b0ad'::uuid,'EF89LP36','Parodiar poemas conhecidos da literatura e criar textos em versos (como haicais, poemas concretos, ciberpoemas, dentre outros).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('d5cc4dac-e800-4c59-9d52-ffd11db85575'::uuid,'EF89LP37','Analisar os efeitos de sentido do uso de figuras de linguagem como ironia, eufemismo, antítese, aliteração, assonância, dentre outras.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('16271f67-1266-4ff6-af4a-e0aa9e570026'::uuid,'EF06LP12','Utilizar, ao produzir texto, recursos de coesão referencial (nome e pronomes), recursos de semântica (sinonímia, antonímia e homonímia) e mecanismos de representação de diferentes vozes (discurso direto e indireto).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','75bea034-3427-4e98-896d-23493d36a84e'::uuid),
	 ('a6c7bf0a-de1f-465e-a735-7c415004a501'::uuid,'EF08LP03','Produzir artigos de opinião, tendo em vista o contexto de produção dado, assumindo posição diante de tema polêmico, argumentando de acordo com a estrutura própria desse tipo de texto e utilizando diferentes tipos de argumentos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('d6a5e4ac-dfdb-4ba5-83eb-c9600ac92cd6'::uuid,'EF08LP04','Utilizar, ao produzir texto, conhecimentos linguísticos e gramaticais: ortografia, regências e concordâncias nominal e verbal, modos e tempos verbais, pontuação etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('9d2f6ede-afc3-4ff2-92c1-c6405f268232'::uuid,'EF08LP05','Analisar processos de formação de palavras por composição (aglutinação e justaposição), apropriando-se de regras básicas de uso do hífen em palavras compostas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('161f9dd8-8cb8-425c-819f-ae10640ea787'::uuid,'EF08LP06','Identificar, em textos lidos ou de produção própria, os termos constitutivos da oração (sujeito e seus modificadores, verbo e seus complementos e modificadores).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('8f3c277a-2bad-44fd-a21e-d0b46ee62d0a'::uuid,'EF08LP07','Diferenciar, em textos lidos ou de produção própria, complementos de adjuntos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('5a5b256f-0e04-4d1a-a2d2-7298ce816796'::uuid,'EF08LP08','Identificar, em textos lidos ou de produção própria, verbos na voz ativa e na voz passiva, interpretando os efeitos de sentido de sujeito ativo e passivo (agente da passiva).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('6977b733-bc74-4d62-ae8e-41b89102fd01'::uuid,'EF08LP09','Interpretar efeitos de sentido de modificadores (adjuntos adnominais e adverbiais) em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('960cbfcc-f166-40c7-bbb6-f79a7859ef95'::uuid,'EF08LP10','Interpretar, em textos lidos ou de produção própria, efeitos de sentido de modificadores do verbo (adjuntos adverbiais – tempo, lugar, modo, causa etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('4573aa50-e1ec-455b-aa4e-247226fb006f'::uuid,'EF08LP11','Identificar, em textos lidos ou de produção própria, agrupamento de orações em períodos, diferenciando coordenação de subordinação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('184155cd-9c5b-4f62-ba1c-5b4757b048cd'::uuid,'EF08LP12','Identificar, em textos lidos, orações subordinadas com conjunções de uso frequente, incorporando-as às suas próprias produções.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('470a719b-3f95-4aa3-92cd-58f93d0892af'::uuid,'EF08LP13','Inferir efeitos de sentido decorrentes do uso de recursos de coesão sequencial: conjunções e articuladores textuais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('8c9d9058-59ef-44b4-9ec2-06b46d179b44'::uuid,'EF08LP14','Utilizar, ao produzir texto, recursos de coesão sequencial (articuladores) e referencial (léxica e pronominal), construções passivas e impessoais, discurso direto e indireto e outros recursos expressivos adequados ao gênero textual.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('3d22dab0-e85b-4cb1-a6ea-6e0c8213bb2d'::uuid,'EF08LP15','Estabelecer relações entre partes do texto, identificando o antecedente de um pronome relativo ou o referente comum de uma cadeia de substituições lexicais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid);
