INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('98180ad8-c95c-4a13-9d32-7efa7e76bd50'::uuid,'EF15_D18','Calcular o resultado de uma multiplicação ou divisão de números naturais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('6fb144d0-b8b4-49b5-889e-68357a614d18'::uuid,'2P1.1','H5 - Ler palavras no padr??o can??nico.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('d29269a5-34c5-4cce-bd73-8ffc99365a8f'::uuid,'EF15_D19','Resolver problema com números naturais, envolvendo diferentes significados da adição ou subtração: juntar, alteração de um estado inicial (positiva ou negativa), comparação e mais de uma transformação (positiva ou negativa).','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('eb5593f2-23fc-4746-9ab6-8f14806f308f'::uuid,'EF15_D20','Resolver problema com números naturais, envolvendo diferentes significados da multiplicação ou divisão: multiplicação comparativa, idéia de proporcionalidade, configuração retangular e combinatória.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('6512142c-0b69-4ae5-b457-bb97bdfeac19'::uuid,'EF15_D21','Identificar diferentes representações de um mesmo número racional.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('61a462c5-a6b0-41a1-9a6d-c5d0aaf57188'::uuid,'EF15_D22','Identificar a localização de números racionais representados na forma decimal na reta numérica.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('89cfe9ca-1200-405a-9ea2-9c196c620bc9'::uuid,'EF15_D23','Resolver problema utilizando a escrita decimal de cédulas e moedas do sistema monetário brasileiro.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('e4e4f007-5196-451c-892a-2584719521f1'::uuid,'EF15_D24','Identificar fração como representação que pode estar associada a diferentes significados.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('f0d1d144-ac66-4c46-9c1d-ab00e8508ec4'::uuid,'EF15_D25','Resolver problema com números racionais expressos na forma decimal envolvendo diferentes significados da adição ou subtração.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('d601f508-5218-4418-916e-9f144aae4e4e'::uuid,'EF15_D26','Resolver problema envolvendo noções de porcentagem (25%, 50%, 100%).','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('508d0d96-60fa-4a6b-88d8-48327d310cd2'::uuid,'EF15_D27','Ler informações e dados apresentados em tabelas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('8d9e0a28-df93-4646-8894-b44a45aac4e2'::uuid,'EF15_D28','Ler informações e dados apresentados em gráficos (particularmente em gráficos de colunas).','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d',NULL),
	 ('d7d2b866-f0c0-4713-8dc3-0b9d7e39d7ba'::uuid,'EF01MA01','Utilizar números naturais como indicador de quantidade ou de ordem em diferentes situações cotidianas e reconhecer situações em que os números não indicam contagem nem ordem, mas sim código de identificação.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('809415b3-f3d1-45eb-b040-9132830d6a48'::uuid,'EF01MA03','Estimar e comparar quantidades de objetos de dois conjuntos (em torno de 20 elementos), por estimativa e/ou por correspondência (um a um, dois a dois) para indicar "tem mais", "tem menos" ou "tem a mesma quantidade".','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('3720f38b-e607-4b0f-a478-872a0b402e2c'::uuid,'EF01MA04','Contar a quantidade de objetos de coleções até 100 unidades e apresentar o resultado por registros verbais e simbólicos, em situações de seu interesse, como jogos, brincadeiras, materiais da sala de aula, entre outros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('62e70892-00a7-479f-80dc-bb3b38bee86c'::uuid,'EF01MA05','Comparar números naturais de até duas ordens em situações cotidianas, com e sem suporte da reta numérica.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('78f020a9-83b5-4784-899b-e6735a023496'::uuid,'EF01MA06','Construir fatos básicos da adição e utilizá-los em procedimentos de cálculo para resolver problemas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('c96169f0-7efe-4d0e-a795-f9c7238f1cca'::uuid,'EF01MA07','Compor e decompor número de até duas ordens, por meio de diferentes adições, com o suporte de material manipulável, contribuindo para a compreensão de características do sistema de numeração decimal e o desenvolvimento de estratégias de cálculo.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('b090f53c-6935-4264-b83b-cdd4dc0b23bf'::uuid,'EF01MA08','Resolver e elaborar problemas de adição e de subtração, envolvendo números de até dois algarismos, com os significados de juntar, acrescentar, separar e retirar, com o suporte de imagens e/ou material manipulável, utilizando estratégias e formas de registro pessoais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('5c0cd777-89ab-4a1d-ada0-5e8a3a7026ed'::uuid,'EF01MA09','Organizar e ordenar objetos familiares ou representações por figuras, por meio de atributos, tais como cor, forma e medida.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('6120fc66-08da-4a0e-819c-7c3585e821e1'::uuid,'EF01MA10','Descrever, após o reconhecimento e a explicitação de um padrão (ou regularidade), os elementos ausentes em sequências recursivas de números naturais, objetos ou figuras.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('6fe80ffd-7ef7-482c-a229-96fabca38575'::uuid,'EF01MA11','Descrever a localização de pessoas e de objetos no espaço em relação à sua própria posição, utilizando termos como à direita, à esquerda, em frente, atrás.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('74224091-658d-4526-95c1-156cd8cf3fa5'::uuid,'EF01MA12','Descrever a localização de pessoas e de objetos no espaço segundo um dado ponto de referência, compreendendo que, para a utilização de termos que se referem à posição, como direita, esquerda, em cima, em baixo, é necessário explicitar-se o referencial.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('fb845a55-260e-4822-8401-cf302ac75020'::uuid,'EF01MA13','Relacionar figuras geométricas espaciais (cones, cilindros, esferas e blocos retangulares) a objetos familiares do mundo físico.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('88189a09-bce4-44da-a78f-81f3b2725314'::uuid,'EF01MA14','Identificar e nomear figuras planas (círculo, quadrado, retângulo e triângulo) em desenhos, jogos e em diferentes representações artísticas e desenhos apresentados em diferentes disposições ou em sólidos geométricos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('61754a8d-d6e1-40a5-8e9a-6c7c19a3a37f'::uuid,'EF01MA16','Relatar em linguagem verbal ou não verbal sequência de acontecimentos relativos a um dia, utilizando, quando possível, os horários dos eventos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('3737e76e-9301-4421-a47c-0fdebf852c71'::uuid,'EF01MA17','Reconhecer e relacionar períodos do dia, dias da semana e meses do ano, utilizando calendário, quando necessário.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('378fddf7-9168-40b8-9e55-027f8faed891'::uuid,'EF01MA18','Produzir a escrita de uma data, apresentando o dia, o mês e o ano, e indicar o dia da semana de uma data, consultando calendários.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('9544b313-d13b-4379-8058-931477f59cfc'::uuid,'EF01MA19','Reconhecer e relacionar valores de moedas e cédulas do sistema monetário brasileiro para resolver situações simples do cotidiano do estudante.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('928af4a9-5d13-4bd8-a666-f7b632bc4489'::uuid,'EF01MA20','Classificar eventos envolvendo o acaso, tais como "acontecerá com certeza", "talvez aconteça" e "é impossível acontecer", em situações do cotidiano.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('44deaa0b-5ac0-4294-a7a9-5e564efdfa93'::uuid,'EF01MA21','Ler dados expressos em tabelas e em gráficos de colunas simples.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('d832b415-d7d5-40a1-8137-20a2ad746139'::uuid,'EF01MA22','Realizar pesquisa, envolvendo até duas variáveis categóricas de seu interesse e universo de até 30 elementos, e organizar dados por meio de representações pessoais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('f3a34295-1b4e-407a-9d16-f971bb1824b8'::uuid,'EF02MA01','Comparar e ordenar números naturais (até a ordem de centenas) pela compreensão de características do sistema de numeração decimal (valor posicional e função do zero).','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a6302150-669a-4895-b83d-02a98578e778'::uuid,'EF02MA02','Fazer estimativas por meio de estratégias diversas a respeito da quantidade de objetos de coleções e registrar o resultado da contagem desses objetos (até 1000 unidades).','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('9aeeac24-aa4c-4d9d-9a69-8f1679c9f031'::uuid,'EF02MA03','Comparar quantidades de objetos de dois conjuntos, por estimativa e/ou por correspondência (um a um, dois a dois, entre outros), para indicar "tem mais", "tem menos" ou "tem a mesma quantidade", indicando, quando for o caso, quantos a mais e quantos a menos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('3a2f6bef-8725-489b-b45d-b095c580a500'::uuid,'EF02MA04','Compor e decompor números naturais de até três ordens, com suporte de material manipulável, por meio de diferentes adições.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('d2093d17-6368-4504-ab00-ea7b9e10b22c'::uuid,'EF02MA05','Construir fatos básicos da adição e subtração e utilizá-los no cálculo mental ou escrito.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('e9675f35-8e9b-42ce-bceb-36414792135d'::uuid,'EF02MA06','Resolver e elaborar problemas de adição e de subtração, envolvendo números de até três ordens, com os significados de juntar, acrescentar, separar, retirar, utilizando estratégias pessoais ou convencionais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('b04f7b6c-b05e-4180-b6f2-8d0d3cfa3f55'::uuid,'EF02MA07','Resolver e elaborar problemas de multiplicação (por 2, 3, 4 e 5) com a ideia de adição de parcelas iguais por meio de estratégias e formas de registro pessoais, utilizando ou não suporte de imagens e/ou material manipulável.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('0af134fb-2ea7-4ba2-8a57-55689d7f8c0e'::uuid,'EF02MA08','Resolver e elaborar problemas envolvendo dobro, metade, triplo e terça parte, com o suporte de imagens ou material manipulável, utilizando estratégias pessoais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('d29ba314-fca4-4265-9fea-d6864c9234ff'::uuid,'EF02MA09','Construir sequências de números naturais em ordem crescente ou decrescente a partir de um número qualquer, utilizando uma regularidade estabelecida.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a7fe5341-7ade-447c-8607-a66a5dc9f03d'::uuid,'EF02MA10','Descrever um padrão (ou regularidade) de sequências repetitivas e de sequências recursivas, por meio de palavras, símbolos ou desenhos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('e4899ddf-07e9-4d1c-8142-e31385f8ed07'::uuid,'EF02MA11','Descrever os elementos ausentes em sequências repetitivas e em sequências recursivas de números naturais, objetos ou figuras.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a06c8a45-5f0a-49bb-b6a8-a9fb20da1727'::uuid,'EF02MA12','Identificar e registrar, em linguagem verbal ou não verbal, a localização e os deslocamentos de pessoas e de objetos no espaço, considerando mais de um ponto de referência, e indicar as mudanças de direção e de sentido.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('6cf3aeef-0512-41fb-a7c8-f4b7ac8ebfc3'::uuid,'EF02MA13','Esboçar roteiros a ser seguidos ou plantas de espaços familiares, considerando relações de direção e de sentido, e de tamanho.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('2e6cd8f1-13d3-4d0e-a868-b68e17301e8e'::uuid,'EF02MA14','Reconhecer, nomear e comparar figuras geométricas espaciais (cubo, bloco retangular, pirâmide, cone, cilindro e esfera), relacionando-as com objetos do mundo físico.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('60893cdd-b5de-40f9-872a-6ec37543d0ed'::uuid,'EF02MA15','Reconhecer, comparar e nomear figuras planas (círculo, quadrado, retângulo e triângulo), por meio de características comuns, em desenhos, objetos do mundo físico e em sólidos geométricos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('de2f38df-a844-4428-89f5-88e805933a60'::uuid,'EF02MA16','Estimativas, medir e comparar comprimentos de lados de salas (incluindo contorno) e de polígonos, utilizando unidades de medida não padronizadas e padronizadas (metro, centímetro e milímetro) e instrumentos adequados.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('f074aacf-03d4-4027-97dd-40e39026f03e'::uuid,'EF02MA17','Estimar, medir e comparar capacidades e massas, utilizando estratégias pessoais e unidades de medida não padronizadas ou padronizadas (litro, mililitro, grama e quilograma).','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a9bd00a0-cc68-433d-8b6d-1db6ab183a76'::uuid,'EF02MA18','Indicar a duração de intervalos de tempo entre duas datas, como dias da semana e meses do ano, utilizando calendário, para planejamentos e organização de agenda.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('dea1f5eb-ee7c-4794-9342-4a51e82db66a'::uuid,'EF02MA19','Medir a duração de um intervalo de tempo por meio de relógio digital e registrar o horário do início e do fim do intervalo.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('db6bd7c6-91a4-4707-8bb5-072d9e22e6d6'::uuid,'EF02MA20','Estabelecer a equivalência de valores entre moedas e cédulas do sistema monetário brasileiro para resolver situações cotidianas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('66fddbfd-4cef-4973-a037-c33bd94a8dcb'::uuid,'EF02MA21','Classificar resultados de eventos cotidianos aleatórios como "pouco prováveis", "muito prováveis", "improváveis" e "impossíveis".','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('ba60e03f-6868-4569-8760-394c45434877'::uuid,'EF02MA22','Comparar informações de pesquisas apresentadas por meio de tabelas de dupla entrada e em gráficos de colunas simples ou barras, para melhor compreender aspectos da realidade próxima.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('e2f63578-b0dd-4529-9979-0241545ecfec'::uuid,'EF02MA23','Realizar pesquisa em universo de até 30 elementos, escolhendo até três variáveis categóricas de seu interesse, organizando os dados coletados em listas, tabelas e gráficos de colunas simples.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('ee4e3f6d-cec9-46b7-ba94-f11b5c036f83'::uuid,'EF03MA01','Ler, escrever e comparar números naturais de até a ordem de unidade de milhar, estabelecendo relações entre os registros numéricos e em língua materna.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('4f44ae2e-6148-4e7a-bc53-f33b2d694fea'::uuid,'EF03MA02','Identificar características do sistema de numeração decimal, utilizando a composição e a decomposição de número natural de até quatro ordens.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('6ec300c8-1f27-4f39-8939-41aca3ce1c60'::uuid,'EF03MA03','Construir e utilizar fatos básicos da adição e da multiplicação para o cálculo mental ou escrito.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('e2460d9c-8ce9-4761-abd8-a098c075e261'::uuid,'EF03MA04','Estabelecer a relação entre números naturais e a reta numérica para ordená-los.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('a2636691-e4dd-4771-a178-142405469dfb'::uuid,'EF03MA05','Utilizar diferentes procedimentos de cálculo mental e escrito para resolver problemas significativos envolvendo adição e subtração com números naturais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('cf6b55f3-2b35-4e38-adb8-6ddb7fe3f29b'::uuid,'EF03MA06','Resolver e elaborar problemas de adição e subtração com os significados de juntar, acrescentar, separar, retirar, comparar e completar quantidades, utilizando diferentes estratégias de cálculo exato ou aproximado, incluindo cálculo mental.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('8295f3ce-ba7c-4839-8421-3c7962c82981'::uuid,'2P1.2','H6 - Ler palavras nos padr??es n??o can??nicos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('dc6053cf-7c5c-4687-aad5-62528216cef4'::uuid,'EF03MA07','Resolver e elaborar problemas de multiplicação (por 2, 3, 4, 5 e 10) com os significados de adição de parcelas iguais e elementos apresentados em disposição retangular, utilizando diferentes estratégias de cálculo e registros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('b03e388c-701d-48b3-a934-5743933037fd'::uuid,'EF03MA08','Resolver e elaborar problemas de divisão de um número natural por outro (até 10), com resto zero e com resto diferente de zero, com os significados de repartição equitativa e de medida, por meio de estratégias e registros pessoais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('0cb243c3-1d29-4e4e-86ec-5439a16dd9e0'::uuid,'EF03MA09','Associar o quociente de uma divisão com resto zero de um número natural por 2, 3, 4, 5 e 10 às ideias de metade, terça, quarta, quinta e décima partes.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('16e5b7ff-ecca-4ca1-9427-54600415fe00'::uuid,'EF03MA10','Identificar regularidades em sequências ordenadas de números naturais, resultantes da realização de adições ou subtrações sucessivas, por um mesmo número, descrever uma regra de formação da sequência e determinar elementos faltantes ou seguintes.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('c42a9257-66c2-4029-8e36-ce1f59da8848'::uuid,'EF03MA11','Compreender a ideia de igualdade para escrever diferentes sentenças de adições ou de subtrações de dois números naturais que resultem na mesma soma ou diferença.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('737d410b-9b44-40f4-9e95-f2e5b532a4fd'::uuid,'EF03MA12','Descrever e representar, por meio de esboços de trajetos ou utilizando croquis e maquetes, a movimentação de pessoas ou de objetos no espaço, incluindo mudanças de direção e sentido, com base em diferentes pontos de referência.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('968c1231-3c28-49c1-8bf8-f726b8d16af4'::uuid,'EF03MA13','Associar figuras geométricas espaciais (cubo, bloco retangular, pirâmide, cone, cilindro e esfera) a objetos do mundo físico e nomear essas figuras.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('4e8d1bbc-094c-4b10-a865-99658626e880'::uuid,'EF03MA14','Descrever características de algumas figuras geométricas espaciais (prismas retos, pirâmides, cilindros, cones), relacionando-as com suas planificações.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('5aaddc04-2225-45ed-91df-0d6428fb415a'::uuid,'EF03MA15','Classificar figuras planas em polígonos e não polígonos, considerando lados e vértices, e nomear triângulos, quadriláteros e pentágonos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('144922d9-d2e2-4a57-9a5b-e5b08caf0ac1'::uuid,'EF03MA16','Reconhecer figuras congruentes, usando sobreposição e desenhos em malhas quadriculadas ou triangulares, incluindo o uso de tecnologias digitais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('781acda9-53fb-4400-acc5-3e7d21aa6d2d'::uuid,'EF03MA18','Escolher a unidade de medida e o instrumento mais apropriado para medições de comprimento, tempo e capacidade.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('aaac9c6f-4233-43d4-9937-ec6ed9e0aaea'::uuid,'EF02LP02','Segmentar palavras em sílabas e remover e substituir sílabas iniciais, mediais ou finais para criar novas palavras.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a9335aaa-4dc0-47e5-95b4-ac89d857e7b2'::uuid,'EF02LP04','Ler e escrever corretamente palavras com sílabas CV, V, CVC, CCV, identificando que existem vogais em todas as sílabas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('f00a55e4-d6ea-4126-a831-87b726bdb247'::uuid,'EF03MA19','Estimar, medir e comparar comprimentos, utilizando unidades de medida não padronizadas e padronizadas mais usuais (metro, centímetro e milímetro) e diversos instrumentos de medida.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('d54900ef-e9bf-4497-bc34-c84eacdc19ae'::uuid,'EF03MA20','Estimar e medir capacidade e massa, utilizando unidades de medida não padronizadas e padronizadas mais usuais (litro, mililitro, quilograma, grama e miligrama), reconhecendo-as em leitura de rótulos e embalagens, entre outros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('54820510-b311-4119-b3a0-1c48e675f980'::uuid,'EF03MA21','Comparar, visualmente ou por superposição, áreas de faces de objetos, de figuras planas ou de desenhos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('d4e77102-349f-4bc5-b39c-fe5b13eeaeff'::uuid,'EF03MA22','Ler e registrar medidas e intervalos de tempo, utilizando relógios (analógico e digital) para informar os horários de início e término de realização de uma atividade e sua duração.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('2b69476a-ee26-4601-b1b6-97f97f326181'::uuid,'EF03MA23','Ler horas em relógios digitais e em relógios analógicos e reconhecer a relação entre hora e minutos e entre minuto e segundos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('eb9eec9e-d169-4725-bd3b-26ec989c936f'::uuid,'EF03MA24','Resolver e elaborar problemas que envolvam a comparação e a equivalência de valores monetários do sistema brasileiro em situações de compra, venda e troca.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('d2c27df6-d344-4dba-94af-a176990ed0c7'::uuid,'EF03MA25','Identificar, em eventos familiares aleatórios, todos os resultados possíveis, estimando os que têm maiores ou menores chances de ocorrência.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('9a85da35-adfe-4111-b9a1-bce1ae9fea6e'::uuid,'EF03MA26','Resolver problemas cujos dados estão apresentados em tabelas de dupla entrada, gráficos de barras ou de colunas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('32810cf1-4e7e-4a66-9d1d-eb81b2ca746b'::uuid,'EF03MA27','Ler, interpretar e comparar dados apresentados em tabelas de dupla entrada, gráficos de barras ou de colunas, envolvendo resultados de pesquisas significativas, utilizando termos como maior e menor frequência, apropriando-se desse tipo de linguagem para compreender aspectos da realidade sociocultural significativos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('113f8cf5-d2f7-4fad-87a9-98cf5b7622bf'::uuid,'EF03MA28','Realizar pesquisa envolvendo variáveis categóricas em um universo de até 50 elementos, organizar os dados coletados utilizando listas, tabelas simples ou de dupla entrada e representá-los em gráficos de colunas simples, com e sem uso de tecnologias digitais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('f4bb1186-07e7-43ae-bbf2-11389abb7864'::uuid,'EF04MA01','Ler, escrever e ordenar números naturais até a ordem de dezenas de milhar.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('3a1ed7ba-812e-4632-9ab0-d0195c6e5942'::uuid,'EF04MA03','Resolver e elaborar problemas com números naturais envolvendo adição e subtração, utilizando estratégias diversas, como cálculo, cálculo mental e algoritmos, além de fazer estimativas do resultado.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('21a46d86-d119-49f5-9603-fbe81876303c'::uuid,'EF04MA04','Utilizar as relações entre adição e subtração, bem como entre multiplicação e divisão, para ampliar as estratégias de cálculo.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('2d2e2273-f22f-4b83-8f91-a759c49ae3d0'::uuid,'EF04MA05','Utilizar as propriedades das operações para desenvolver estratégias de cálculo.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('bf5f93b8-5a3d-4487-a181-fe79d4e42def'::uuid,'EF04MA06','Resolver e elaborar problemas envolvendo diferentes significados da multiplicação (adição de parcelas iguais, organização retangular e proporcionalidade), utilizando estratégias diversas, como cálculo por estimativa, cálculo mental e algoritmos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('ef7a16ec-c889-4abe-8d5f-15d42a831441'::uuid,'EF04MA07','Resolver e elaborar problemas de divisão cujo divisor tenha no máximo dois algarismos, envolvendo os significados de resultado de uma medida e de partição equitativa, utilizando estratégias diversas, como cálculo por estimativa, cálculo mental e algoritmos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('fbf89b2f-9802-4fa1-a907-969d58254ae9'::uuid,'EF04MA08','Resolver, com o suporte de imagem e/ou material manipulável, problemas simples de contagem, como a determinação do número de agrupamentos possíveis ao se combinar cada elemento de uma coleção com todos os elementos de outra, utilizando estratégias e formas de registro pessoais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('9519a986-77f8-40e3-93ca-f993d11b5c62'::uuid,'EF04MA09','Reconhecer as frações unitárias mais usuais (1/2, 1/3, 1/4, 1/5, 1/10 e 1/100) como unidades de medida menores do que uma unidade, utilizando a reta numérica como recurso.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('da97aef9-7324-451b-a45b-575bbd97ec72'::uuid,'EF04MA10','Reconhecer que as regras do sistema de numeração decimal podem ser estendidas para a representação decimal de um número racional e relacionar décimos e centésimos com a representação do sistema monetário brasileiro.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('155d9644-bd17-4fb6-8907-4962b8f375f9'::uuid,'EF04MA11','Identificar regularidades em sequências numéricas compostas por múltiplos de um número natural.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('84a53f25-1234-458c-8426-9cf096afea18'::uuid,'EF04MA12','Reconhecer, por meio de investigações, que há grupos de números naturais para os quais as divisões por um determinado número resultam em restos iguais, identificando regularidades.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('7ddd1d1b-446e-4c42-bab9-fdd34353fd99'::uuid,'EF04MA13','Reconhecer, por meio de investigações, utilizando a calculadora quando necessário, as relações inversas entre as operações de adição e de subtração e de multiplicação e de divisão, para aplicá-las na resolução de problemas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('e6ca28ce-17cc-4bbf-b69e-92ca7f85c736'::uuid,'EI03EO11','Participar de atividades coletivas, demonstrando interesse e coopera????o.','8687630b-09b0-4d2e-ba3c-096125160e42','35e6701a-87b9-4c46-82e5-44aa3458dd60'::uuid),
	 ('bf9f135f-e729-4f89-a5ae-b260e76d5e62'::uuid,'EF04MA14','Reconhecer e mostrar, por meio de exemplos, que a relação de igualdade existente entre dois termos permanece quando se adiciona ou se subtrai um mesmo número a cada um desses termos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('7840e7fe-8f95-4fa3-8bcb-cb8b172dfded'::uuid,'EF04MA15','Determinar o número desconhecido que torna verdadeira uma igualdade que envolve as operações fundamentais com números naturais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('78571519-9f9b-497a-b497-2f50a05cb45a'::uuid,'EF04MA16','Descrever deslocamentos e localização de pessoas e de objetos no espaço, por meio de malhas quadriculadas e representações como desenhos, mapas, planta baixa e croquis, empregando termos como direita e esquerda, mudanças de direção e sentido, intersecção, transversais, paralelas e perpendiculares.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
