	 ('f81daba8-2760-48ab-9da3-86d1ae3d9dd8'::uuid,'EI03EO09','Reconhecer e valorizar as caracter??sticas de seu corpo e de seus colegas, respeitando as diferen??as.','2fec15b8-75d9-4dab-95e5-6bee4e8e8cbf','b3f73bca-27a7-4c86-8856-949056773776'::uuid),
	 ('01788ed9-e026-4e7f-934d-b05aac77db2c'::uuid,'EF02LP15','Cantar cantigas e canções, obedecendo ao ritmo e à melodia.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a62153a0-122a-4c95-835b-2571b11c944a'::uuid,'EF04MA19','Reconhecer simetria de reflexão em figuras e em pares de figuras geométricas planas e utilizá-la na construção de figuras congruentes, com o uso de malhas quadriculadas e de softwares de geometria.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('94b494d6-1b82-48c8-ae2c-06f075432cd1'::uuid,'EF04MA20','Medir e estimar comprimentos (incluindo perímetros), massas e capacidades, utilizando unidades de medida padronizadas mais usuais, valorizando e respeitando a cultura local.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('087d7865-8ad8-48c1-960c-1b6d2ea0cb13'::uuid,'EF04MA21','Medir, comparar e estimar área de figuras planas desenhadas em malha quadriculada, pela contagem dos quadradinhos ou de metades de quadradinho, reconhecendo que duas figuras com formatos diferentes podem ter a mesma área.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('9af5b9f6-ca3e-4a0f-88d2-d89fe6ac7f8b'::uuid,'EF04MA22','Ler e registrar medidas e intervalos de tempo em horas, minutos e segundos em situações relacionadas ao seu cotidiano, como informar os horários de início e término de realização de uma tarefa e sua duração.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('5fba879e-2432-4179-906e-5ecbbaa6215d'::uuid,'EF04MA23','Reconhecer temperatura como grandeza e o grau Celsius como unidade de medida a ela associada e utilizá-lo em comparações de temperaturas em diferentes regiões do Brasil ou no exterior ou, ainda, em discussões sobre o aquecimento global.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('5b7548e7-d5ff-4727-b6cc-f873b46fe848'::uuid,'EF04MA24','Registrar as temperaturas máxima e mínima diárias, em locais do seu cotidiano, e elaborar gráficos de colunas com as variações diárias e mensais das temperaturas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('66c61e7c-36af-4a72-95a1-6680ebca88d8'::uuid,'EF04MA25','Resolver e elaborar problemas que envolvam situações de compra e venda e formas de pagamento, utilizando termos como troco e desconto, enfatizando o consumo ético, consciente e responsável.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('e2802b39-d6b8-4d93-b1cf-7a6ea98433fe'::uuid,'EF04MA26','Identificar, entre eventos aleatórios cotidianos, aqueles que têm maior chance de ocorrência, reconhecendo características de resultados mais prováveis, sem utilizar frações.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('c5e95440-5881-42c5-9d4e-e670bd1c3c77'::uuid,'EF04MA27','Analisar dados apresentados em tabelas simples ou de dupla entrada e em gráficos de colunas ou pictóricos, com base em informações das diferentes áreas do conhecimento, e produzir texto com a síntese de sua análise.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('cb0f60c9-baa8-4ba2-af80-696e0f7fc3c9'::uuid,'EF04MA28','Realizar pesquisa envolvendo variáveis categóricas e numéricas e organizar dados coletados por meio de tabelas e gráficos de colunas simples ou agrupadas, com e sem uso de tecnologias digitais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('695f8ad4-727e-4639-904f-748b7b5b4968'::uuid,'EF05MA01','Ler, escrever e ordenar números naturais até a ordem das centenas de milhar com compreensão das principais características do sistema de numeração decimal.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('9547ea0b-0430-4f7f-88db-4c38fbd8509a'::uuid,'EF05MA02','Ler, escrever e ordenar números racionais na forma decimal com compreensão das principais características do sistema de numeração decimal, utilizando, como recursos, a composição e decomposição e a reta numérica.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('9298b78c-95f7-437b-b4f9-ebe3f5aed8fd'::uuid,'EF05MA03','Identificar e representar frações (menores e maiores que a unidade), associando-as ao resultado de uma divisão ou à ideia de parte de um todo, utilizando a reta numérica como recurso.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('a87c4203-6960-441a-aa28-8b0fa1bf18d1'::uuid,'EF05MA04','Identificar frações equivalentes.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('3490fadf-8784-4e14-b31e-871409d582ca'::uuid,'EF05MA05','Comparar e ordenar números racionais positivos (representações fracionária e decimal), relacionando-os a pontos na reta numérica.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('37b0c5db-5415-465b-9d6e-37710f20c4e3'::uuid,'EF05MA06','Associar as representações 10%, 25%, 50%, 75% e 100% respectivamente à décima parte, quarta parte, metade, três quartos e um inteiro, para calcular porcentagens, utilizando estratégias pessoais, cálculo mental e calculadora, em contextos de educação financeira, entre outros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('89381268-2bbe-4f81-be9b-30cdb5cd2e1d'::uuid,'EF05MA07','Resolver e elaborar problemas de adição e subtração com números naturais e com números racionais, cuja representação decimal seja finita, utilizando estratégias diversas, como cálculo por estimativa, cálculo mental e algoritmos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('3b6ce25b-4a32-4908-8dec-f87a6b3a6e2d'::uuid,'EF05MA08','Resolver e elaborar problemas de multiplicação e divisão com números naturais e com números racionais cuja representação decimal é finita (com multiplicador natural e divisor natural e diferente de zero), utilizando estratégias diversas, como cálculo por estimativa, cálculo mental e algoritmos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('b4fe22de-dcd7-4770-860a-b10464d19f6b'::uuid,'EF05MA09','Resolver e elaborar problemas simples de contagem envolvendo o princípio multiplicativo, como a determinação do número de agrupamentos possíveis ao se combinar cada elemento de uma coleção com todos os elementos de outra coleção, por meio de diagramas de árvore ou de tabelas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('16c34693-9258-4cfd-b818-67ab9697f82e'::uuid,'EF05MA10','Concluir, por meio de investigações, que a relação de igualdade existente entre dois membros permanece ao adicionar, subtrair, multiplicar ou dividir cada um desses membros por um mesmo número, para construir a noção de equivalência.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('33edf223-f78c-4088-bbb8-8a3be475b42d'::uuid,'EF05MA11','Resolver e elaborar problemas cuja conversão em sentença matemática seja uma igualdade com uma operação em que um dos termos é desconhecido.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('b42b2ca0-516d-430a-b131-94a034a32d1a'::uuid,'EF05MA12','Resolver problemas que envolvam variação de proporcionalidade direta entre duas grandezas, para associar a quantidade de um produto ao valor a pagar, alterar as quantidades de ingredientes de receitas, ampliar ou reduzir escalas em mapas, entre outros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('df91ff00-f687-4e9a-8145-574826a134ff'::uuid,'EF05MA13','Resolver problemas envolvendo a partilha de uma quantidade em duas partes desiguais, tais como dividir uma quantidade em duas partes, de modo que uma seja o dobro da outra, com compreensão da ideia de razão entre as partes e delas com o todo.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('c750edf8-ba41-4c57-8f60-fefc7dcd75f8'::uuid,'EF05MA14','Utilizar e compreender diferentes representações para a localização de objetos no plano, como mapas, células em planilhas eletrônicas e coordenadas geográficas, a fim de desenvolver as primeiras noções de coordenadas cartesianas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('e7931f17-add0-4c92-8a07-1d7c1a4a5255'::uuid,'EF05MA15','Interpretar, descrever e representar a localização ou movimentação de objetos no plano cartesiano (1º quadrante), utilizando coordenadas cartesianas, indicando mudanças de direção e de sentido e giros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('d48c80dc-2a47-496c-bda9-abff1fa7449c'::uuid,'EF05MA16','Associar figuras espaciais a suas planificações (prismas, pirâmides, cilindros e cones) e analisar, nomear e comparar seus atributos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('803ae3ce-eb60-4b71-84c9-43bb5f056163'::uuid,'EF05MA17','Reconhecer, nomear e comparar polígonos, considerando lados, vértices e ângulos, e desenhá-los, utilizando material de desenho ou tecnologias digitais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('a39004f8-474c-419d-86d8-46f08ba5ff21'::uuid,'EF05MA18','Reconhecer a congruência dos ângulos e a proporcionalidade entre os lados correspondentes de figuras poligonais em situações de ampliação e de redução em malhas quadriculadas e usando tecnologias digitais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('c91f33bc-e8eb-4c59-a9ab-b7a05a68a718'::uuid,'EF05MA19','Resolver e elaborar problemas envolvendo medidas das grandezas comprimento, área, massa, tempo, temperatura e capacidade, recorrendo a transformações entre as unidades mais usuais em contextos socioculturais.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('b0e11904-7d75-46f0-86a3-5f9feb926dfb'::uuid,'EF05MA20','Concluir, por meio de investigações, que figuras de perímetros iguais podem ter áreas diferentes e que, também, figuras que têm a mesma área podem ter perímetros diferentes.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('8067e7cb-40f2-4a65-b2da-63f01029fa36'::uuid,'EF05MA21','Reconhecer volume como grandeza associada a sólidos geométricos e medir volumes por meio de empilhamento de cubos, utilizando, preferencialmente, objetos concretos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('ee5a5be9-607e-4332-9ec5-b6b60c818d1c'::uuid,'EF05MA22','Apresentar todos os possíveis resultados de um experimento aleatório, estimando se esses resultados são igualmente prováveis ou não.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('f9263b6e-a0a3-4973-9d00-36a993358df5'::uuid,'EF05MA23','Determinar a probabilidade de ocorrência de um resultado em eventos aleatórios, quando todos os resultados possíveis têm a mesma chance de ocorrer (equiprováveis).','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('e8f41eb4-3ed9-49e2-9662-e0dea6b432f5'::uuid,'EF05MA24','Interpretar dados estatísticos apresentados em textos, tabelas e gráficos (colunas ou linhas), referentes a outras áreas do conhecimento ou a outros contextos, como saúde e trânsito, e produzir textos com o objetivo de sintetizar conclusões.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('6c54861f-c63e-49ed-a1bc-0c7542b117bc'::uuid,'EF05MA25','Realizar pesquisa envolvendo variáveis categóricas e numéricas, organizar dados coletados por meio de tabelas, gráficos de colunas, pictóricos e de linhas, com e sem uso de tecnologias digitais, e apresentar texto escrito sobre a finalidade da pesquisa e a síntese dos resultados.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
