	 ('b1375202-b8ee-4020-928b-103e5307480b'::uuid,'2F1.1','H7  -  Ler  frases  com  estrutura  sint??tica  simples (sujeito, verbo e complemento), na ordem direta.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('9c472fc2-193c-4305-9568-3f2908f362d7'::uuid,'LP9L1.1','Identificar o uso de recursos persuasivos em textos verbais e não verbais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
