	 ('069a493c-0244-4685-920c-7b182bcfc837'::uuid,'LP9L1.4','Identificar teses/opiniões/posicionamento explícitos e argumentos em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
