	 ('0a73321c-91c5-44e8-b9d3-925413b08e23'::uuid,'LP9L2.2','Analisar a intertextualidade entre textos literários ou entre estes e outros textos verbais ou não verbais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('afca8848-b79b-4831-9636-6e9946c8faaa'::uuid,'LP9L2.3','Inferir a presença de valores sociais, culturais e humanos em textos literários.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('a63f49eb-9b11-4bd1-bfdf-8f2c89098240'::uuid,'LP9L2.4','Analisar efeitos de sentido produzido pelo uso de formas de apropriação textual (paráfrase, citação etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid);
