	 ('139c21f3-8899-46f6-a48b-f0d8379872dd'::uuid,'LP9L2.7','Inferir, em textos multissemióticos, efeitos de humor, ironia e/ou crítica.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('c0ba9113-ffbe-4616-80c2-a69caf8de083'::uuid,'LP9L2.8','Analisar marcas de parcialidade em textos jornalísticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
