	 ('13879de8-aa13-40db-959c-144379160f0a'::uuid,'LP9L2.10','Analisar os efeitos de sentido decorrentes dos mecanismos de construção de textos jornalísticos/midiáticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
