	 ('a34b9662-a408-4878-8060-882b687b72af'::uuid,'LP9L3.2','Avaliar a fidedignidade de informações sobre um mesmo fato divulgado em diferentes veículos e mídias.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('14aadb2a-bb55-49f7-806b-e6f3a2cd8ec7'::uuid,'LP9A1.1','Identificar os recursos de modalização em textos diversos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('68cdfb0f-665c-41d3-ad7f-8e745ab3a565'::uuid,'LP9A2.1','Analisar o uso de figuras de linguagem como estratégia argumentativa.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
