	 ('e21f926c-13a3-43e6-b0d9-5fedacc41ea6'::uuid,'LP9A2.3','Analisar os mecanismos que contribuem para a progressão textual.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('bed0d00e-4cd5-422c-946a-37880acf0efb'::uuid,'LP9A2.4','Analisar os processos de referenciação lexical e pronominal.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
