	 ('f5299ff4-0fa2-4cf5-bd8f-116dc94da67f'::uuid,'LP9A3.2','Avaliar a eficácia das estratégias argumentativas em textos de diferentes gêneros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('30002047-1c2e-408c-bb11-b25fb3e9d8dd'::uuid,'LP9A4.1','Pruduzir texto em língua portuguesa, de acordo com o gênero textual e o tema demandados.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
