	 ('cd352536-8ebf-473e-8496-05ee96b1892d'::uuid,'EF07LP12','Reconhecer recursos de coesão referencial: substituições lexicais (de substantivos por sinônimos) ou pronominais (uso de pronomes anafóricos – pessoais, possessivos, demonstrativos).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','4128c187-5e33-4ff9-a96d-e7eb9ddbe04e'::uuid),
	 ('230d9515-f1db-4fd7-9bf0-fef6595c51ec'::uuid,'EF07LP13','Estabelecer relações entre partes do texto, identificando o antecedente de um pronome relativo ou o referente comum de uma cadeia de substituições lexicais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','4128c187-5e33-4ff9-a96d-e7eb9ddbe04e'::uuid),
	 ('3d880e2a-388f-4080-89e7-06ed4a679747'::uuid,'EF07LP14','Identificar, em textos, os efeitos de sentido do uso de estratégias de modalização e argumentatividade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','4128c187-5e33-4ff9-a96d-e7eb9ddbe04e'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('bb17345b-d57d-4020-97b5-fd05f3dd7792'::uuid,'EF08LP01','Identificar e comparar as várias editorias de jornais impressos e digitais e de sites noticiosos, de forma a refletir sobre os tipos de fatos que são noticiados e as escolhas editoriais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('716d6d80-6691-4e16-9e82-ca7d41df4581'::uuid,'EF08LP02','Justificar diferenças ou semelhanças no tratamento dado a uma mesma informação veiculada em textos diferentes, consultando sites e serviços de checadores de fatos (curadoria).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b6760b9b-2758-4d14-a650-c3a30c0aeb3b'::uuid),
	 ('aae85858-13ff-4a03-84e8-b3fb8d048a5a'::uuid,'EI03EO12','Interagir com o meio ambiente, explorando e valorizando a natureza e seus elementos.','3b393985-82d5-46e7-9b5a-6270bedf77ab','35e6701a-87b9-4c46-82e5-44aa3458dd60'::uuid),
	 ('f69f4efb-a982-4ac3-a7c9-d37ab6263da8'::uuid,'EF09LP01','Analisar o fenômeno da disseminação de notícias falsas nas redes sociais e desenvolver estratégias para reconhecê-las, como a checagem da confiabilidade das fontes, a comparação entre diferentes veículos e o uso de ferramentas de curadoria.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('29b7cbde-20a8-46e3-a2ec-7e30f66c22a2'::uuid,'EF09LP02','Analisar e comentar a cobertura da imprensa sobre fatos de relevância social, comparando diferentes enfoques por meio do uso de ferramentas de curadoria.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('8f937579-9ac5-45b2-aeab-9ccacf63e48e'::uuid,'EF09LP03','Produzir artigos de opinião, tendo em vista o contexto de produção dado, assumindo posição diante de tema polêmico, argumentando de acordo com a estrutura própria desse tipo de texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('85f2c2d5-df93-467f-a2ce-fac5a44590b0'::uuid,'EF09LP04','Escrever textos corretamente, de acordo com a norma-padrão, com estruturas sintáticas complexas no nível da oração e do período.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('04477b02-8f9e-4bfc-bc2a-ca46cdf26dd4'::uuid,'EF09LP05','Identificar, em textos lidos e em produções próprias, orações com a estrutura sujeito-verbo de ligação-predicativo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('9a8c0f79-e9e0-48a2-b438-ff43acdf9ec3'::uuid,'EF09LP06','Diferenciar, em textos lidos e em produções próprias, o efeito de sentido do uso de verbos de ligação e de verbos significativos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('04ecaa8f-7458-44a5-9227-e8c3ef04c711'::uuid,'EF09LP07','Identificar, em textos lidos e em produções próprias, a relação que conjunções (e locuções conjuntivas) coordenativas e subordinativas estabelecem entre as orações que conectam.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
