	 ('ee806fa1-74ef-461e-a71c-0d9f4a15a92f'::uuid,'EF09MA05','Resolver e elaborar problemas que envolvam porcentagens, com a ideia de aplica????o de percentuais sucessivos e a determina????o das taxas percentuais, preferencialmente com o uso de tecnologias digitais, no contexto da educa????o financeira.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('23cd6e20-456c-43f7-ae07-0103625f56c9'::uuid,'EF09MA14','Resolver e elaborar problemas de aplica????o do teorema de Pit??goras ou das rela????es de proporcionalidade envolvendo retas paralelas cortadas por secantes.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('2225b428-e875-489d-a358-c37ce97464a5'::uuid,'EF09MA15','Descrever, por escrito e por meio de um fluxograma, um algoritmo para a constru????o de um pol??gono regular cuja medida do lado ?? conhecida, utilizando r??gua e compasso, como tamb??m softwares.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('17295e56-5fc9-4d97-ac16-afc3c248b5a6'::uuid,'EF09MA16','Determinar o ponto m??dio de um segmento de reta e a dist??ncia entre dois pontos quaisquer, dadas as coordenadas desses pontos no plano cartesiano, sem o uso de f??rmulas, e utilizar esse conhecimento para calcular, por exemplo, medidas de per??metros e ??reas de figuras planas constru??das no plano.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('a20c5c51-192f-4853-bcc7-48a93492a1d3'::uuid,'EF09MA18','Reconhecer e empregar unidades usadas para expressar medidas muito grandes ou muito pequenas, tais como dist??ncia entre planetas e sistemas solares, tamanho de v??rus ou de c??lulas, capacidade de armazenamento de computadores, entre outros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('fa8e7b12-058e-4909-801f-7f5c246521b8'::uuid,'EF09MA19','Resolver e elaborar problemas que envolvam medidas de volumes de prismas e de cilindros retos, inclusive com uso de express??es de c??lculo, em situa????es cotidianas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('e2373aaa-f5b6-4b6d-86e0-2a7e0077c918'::uuid,'EF09MA20','Reconhecer, em experimentos aleat??rios, eventos independentes e dependentes e calcular a probabilidade de sua ocorr??ncia, nos dois casos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('63e896b0-6648-4e1c-8b9c-a1cd69f29b63'::uuid,'EF09MA21','Analisar e identificar, em gr??ficos divulgados pela m??dia, os elementos que podem induzir, ??s vezes propositadamente, erros de leitura, como escalas inapropriadas, legendas n??o explicitadas corretamente, omiss??o de informa????es importantes (fontes e datas), entre outros.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('66f6d5e1-4a14-4046-bcd9-e9fc82120b90'::uuid,'EF09MA22','Escolher e construir o gr??fico mais adequado (colunas, setores, linhas), com ou sem uso de planilhas eletr??nicas, para apresentar um determinado conjunto de dados, destacando aspectos como as medidas de tend??ncia central.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('7514858c-9071-472e-b897-4dc327029cad'::uuid,'EF09MA23','Planejar e executar pesquisa amostral envolvendo tema da realidade social e comunicar os resultados por meio de relat??rio contendo avalia????o de medidas de tend??ncia central e da amplitude, tabelas e gr??ficos adequados, constru??dos com o apoio de planilhas eletr??nicas.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('eda6cfef-0473-4541-8962-5c5c8967c4de'::uuid,'9L1.1','Identificar o uso de recursos persuasivos em textos verbais e n??o verbais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('3047b5c4-3bd7-42d6-85c0-8c711d8173e2'::uuid,'9L1.2','Identificar elementos constitutivos de textos pertencentes ao dom??nio jornal??stico/midi??tico.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid);
