	 ('03cd659a-feba-4c38-9aff-2a322a386b2f'::uuid,'9L2.4','Analisar efeitos de sentido produzido pelo uso de formas de apropria????o textual (par??frase, cita????o etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
