	 ('dfcc277c-c537-4316-8d14-f16f8b4ef4ed'::uuid,'9L2.6','Distinguir fatos de opini??es em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('5f0a9461-2a8f-4cc6-b359-f49382027abb'::uuid,'9L2.7','Inferir, em textos multissemi??ticos, efeitos de humor, ironia e/ou cr??tica.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid);
