	 ('79b325ff-b599-4444-84f6-4cfa99f47673'::uuid,'9L3.2','Avaliar a fidedignidade de informa????es sobre um mesmo fato divulgado em diferentes ve??culos e m??dias.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('ec90756a-a802-49cf-99ba-3414bf4a1060'::uuid,'9A1.1','Identificar os recursos de modaliza????o em textos diversos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('4407a81c-6b88-4be1-b7fb-f52d0928bed0'::uuid,'9A2.1','Analisar o uso de figuras de linguagem como estrat??gia argumentativa.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('63b6809b-48b1-40a4-b869-558d0a5ce786'::uuid,'9A2.2','Analisar os efeitos de sentido dos tempos, modos e/ou vozes verbais com base no g??nero textual e na inten????o comunicativa.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('b194286c-84e6-4fcb-829f-de14b12a6ce1'::uuid,'9A2.3','Analisar os mecanismos que contribuem para a progress??o textual.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('a1bba43b-92ee-429d-8f59-9781cbf1fca9'::uuid,'9A2.4','Analisar os processos de referencia????o lexical e pronominal.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid);
