	 ('2ed98d23-939d-49c2-87d7-b6af57fbb140'::uuid,'9A2.5','Analisar as variedades lingu??sticas em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
