	 ('68c86868-3fd0-4135-bdc8-8ae2d3018c5e'::uuid,'9A3.1','Avaliar a adequa????o das variedades lingu??sticas em contextos de uso.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('ac6963e2-5d71-4a88-a1fc-adbb49c37ab9'::uuid,'9A3.2','Avaliar a efic??cia das estrat??gias argumentativas em textos de diferentes g??neros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('1f60e5b6-e903-4b58-bae1-ae2f940df32d'::uuid,'9A4.1','Pruduzir texto em l??ngua portuguesa, de acordo com o g??nero textual e o tema demandados.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','3c68a0b5-9613-469e-8376-6fb678c60363'::uuid),
	 ('798cb96d-96d3-4a29-820f-2973b7364eb5'::uuid,'EF15LP01','Identificar a função social de textos que circulam em campos da vida social dos quais participa cotidianamente (a casa, a rua, a comunidade, a escola) e nas mídias impressa, de massa e digital, reconhecendo para que foram produzidos, onde circulam, quem os produziu e a quem se destinam.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('4bc02974-773e-4ba2-b2a6-52b1eabebcf2'::uuid,'EF15LP02','Estabelecer expectativas em relação ao texto que vai ler (pressuposições antecipadoras dos sentidos, da forma e da função social do texto), apoiando-se em seus conhecimentos prévios sobre as condições de produção e recepção desse texto, o gênero, o suporte e o universo temático, bem como sobre saliências textuais, recursos gráficos, imagens, dados da própria obra (índice, prefácio etc.), confirmando antecipações e inferências realizadas antes e durante a leitura de textos, checando a adequação das hipóteses realizadas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('30161b82-7de1-44a0-94b8-a483d643c8ca'::uuid,'EF15LP03','Localizar informações explícitas em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7143843d-e393-43f9-9770-58b93b3e91a2'::uuid,'EF15LP04','Identificar o efeito de sentido produzido pelo uso de recursos expressivos gráfico-visuais em textos multissemióticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('541b7459-9049-43a2-b683-09f64fdd7ee7'::uuid,'EF01LP01','Reconhecer que textos são lidos e escritos da esquerda para a direita e de cima para baixo da página.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('358b8932-f682-4ab3-ba96-816e5a97367c'::uuid,'EF02LP01','Utilizar, ao produzir o texto, grafia correta de palavras conhecidas ou com estruturas silábicas já dominadas, letras maiúsculas em início de frases e em substantivos próprios, segmentação entre as palavras, ponto final, ponto de interrogação e ponto de exclamação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('855679e7-c536-4af1-bd67-0f535f695821'::uuid,'EF15LP05','Planejar, com a ajuda do professor, o texto que será produzido, considerando a situação comunicativa, os interlocutores (quem escreve/para quem escreve); a finalidade ou o propósito (escrever para quê); a circulação (onde o texto vai circular); o suporte (qual é o portador do texto); a linguagem, organização e forma do texto e seu tema, pesquisando em meios impressos ou digitais, sempre que for preciso, informações necessárias à produção do texto, organizando em tópicos os dados e as fontes pesquisadas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ff2cf1a8-2fc7-4396-8f2b-6b3fdd3d0c63'::uuid,'EF15LP06','Reler e revisar o texto produzido com a ajuda do professor e a colaboração dos colegas, para corrigi-lo e aprimorá- lo, fazendo cortes, acréscimos, reformulações, correções de ortografia e pontuação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ad9a4fbd-d31e-4afb-a0d9-a4f95db8fb6f'::uuid,'EF15LP07','Editar a versão final do texto, em colaboração com os colegas e com a ajuda do professor, ilustrando, quando for o caso, em suporte adequado, manual ou digital.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('a973c15f-bdac-431c-a78b-b72c9b225dd5'::uuid,'EF15LP08','Utilizar software, inclusive programas de edição de texto, para editar e publicar os textos produzidos, explorando os recursos multissemióticos disponíveis.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7ac05c8b-76ba-4ce6-9489-f799fd4fe56f'::uuid,'EF15LP09','Expressar-se em situações de intercâmbio oral com clareza, preocupando-se em ser compreendido pelo interlocutor e usando a palavra com tom de voz audível, boa articulação e ritmo adequado.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('91e2fb41-8959-4336-a2f8-4f46cb34627d'::uuid,'EF15LP10','Escutar, com atenção, falas de professores e colegas, formulando perguntas pertinentes ao tema e solicitando esclarecimentos sempre que necessário.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c3ef65cf-9e2b-4d83-9d19-275b08c6124e'::uuid,'EF15LP11','Reconhecer características da conversação espontânea presencial, respeitando os turnos de fala, selecionando e utilizando, durante a conversação, formas de tratamento adequadas, de acordo com a situação e a posição do interlocutor.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('123fe5cb-2b3c-422c-87f8-783366d586d3'::uuid,'EF15LP12','Atribuir significado a aspectos não linguísticos (paralinguísticos) observados na fala, como direção do olhar, riso, gestos, movimentos da cabeça (de concordância ou discordância), expressão corporal, tom de voz.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ec56bad2-0d87-4613-bee0-5210d175e7ed'::uuid,'EF15LP13','Identificar finalidades da interação oral em diferentes contextos comunicativos (solicitar informações, apresentar opiniões, informar, relatar experiências etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('2c8c9aa2-04f5-443e-ba90-e0fc3991b183'::uuid,'EF15LP14','Construir o sentido de histórias em quadrinhos e tirinhas, relacionando imagens e palavras e interpretando recursos gráficos (tipos de balões, de letras, onomatopeias).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8182a11c-7d42-43ef-8766-7b4951aef11a'::uuid,'EF15LP15','Reconhecer que os textos literários fazem parte do mundo do imaginário e apresentam uma dimensão lúdica, de encantamento, valorizando- os, em sua diversidade cultural, como patrimônio artístico da humanidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('fae1a72f-97d2-4940-b35d-7d9f689d160f'::uuid,'EF15LP16','Ler e compreender, em colaboração com os colegas e com a ajuda do professor e, mais tarde, de maneira autônoma, textos narrativos de maior porte como contos (populares, de fadas, acumulativos, de assombração etc.) e crônicas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b60ba325-09fd-4b9d-ac31-572a336b8771'::uuid,'EF15LP17','Apreciar poemas visuais e concretos, observando efeitos de sentido criados pelo formato do texto na página, distribuição e diagramação das letras, pelas ilustrações e por outros efeitos visuais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8dcf61ff-e2be-45a7-b9ef-a76a2df5409a'::uuid,'EF15LP18','Relacionar texto com ilustrações e outros recursos gráficos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('1f06ada7-5a4f-4e59-94a3-f6d3a965cfd9'::uuid,'EF15LP19','Recontar oralmente, com e sem apoio de imagem, textos literários lidos pelo professor.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c06e218f-7d98-49f0-9973-356ddfd1f27c'::uuid,'EF12LP01','Ler palavras novas com precisão na decodificação, no caso de palavras de uso frequente, ler globalmente, por memorização.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('68906a2e-024b-4ab1-903f-66822bf5a3d0'::uuid,'EF12LP02','Buscar, selecionar e ler, com a mediação do professor (leitura compartilhada), textos que circulam em meios impressos ou digitais, de acordo com as necessidades e interesses.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('91fe2ec8-22f9-42a5-a737-0df468e69148'::uuid,'EF12LP03','Copiar textos breves, mantendo suas características e voltando para o texto sempre que tiver dúvidas sobre sua distribuição gráfica, espaçamento entre as palavras, escrita das palavras e pontuação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('3d71d80a-a0ff-4427-aa44-9122c1454cfe'::uuid,'EF12LP04','Ler e compreender, em colaboração com os colegas e com a ajuda do professor ou já com certa autonomia, listas, agendas, calendários, avisos, convites, receitas, instruções de montagem (digitais ou impressos), dentre outros gêneros do campo da vida cotidiana, considerando a situação comunicativa e o tema/assunto do texto e relacionando sua forma de organização à sua finalidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('0f1352c5-c087-4ec3-ac03-754f0d176b50'::uuid,'EF12LP05','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, (re)contagens de histórias, poemas e outros textos versificados (letras de canção, quadrinhas, cordel), poemas visuais, tiras e histórias em quadrinhos, dentre outros gêneros do campo artístico- literário, considerando a situação comunicativa e a finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f3b812a5-ec34-4ddb-a76f-61b19795269b'::uuid,'EF12LP06','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, recados, avisos, convites, receitas, instruções de montagem, dentre outros gêneros do campo da vida cotidiana, que possam ser repassados oralmente por meio de ferramentas digitais, em áudio ou vídeo, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b03b76e8-12b4-4658-95e1-d25df453a980'::uuid,'EF12LP07','Identificar e (re)produzir, em cantiga, quadras, quadrinhas, parlendas, trava-línguas e canções, rimas, aliterações, assonâncias, o ritmo de fala relacionado ao ritmo e à melodia das músicas e seus efeitos de sentido.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('edb9954d-ce81-4e49-8810-34d7fc8a1400'::uuid,'EF12LP08','Ler e compreender, em colaboração com os colegas e com a ajuda do professor, fotolegendas em notícias, manchetes e lides em notícias, álbum de fotos digital noticioso e notícias curtas para público infantil, dentre outros gêneros do campo jornalístico, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('8d31d5a3-9d9d-4feb-89bd-5f8d5871e65c'::uuid,'EF12LP09','Ler e compreender, em colaboração com os colegas e com a ajuda do professor, slogans, anúncios publicitários e textos de campanhas de conscientização destinados ao público infantil, dentre outros gêneros do campo publicitário, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('cec75864-eca8-4015-8c4a-3a8aabac99da'::uuid,'EF12LP10','Ler e compreender, em colaboração com os colegas e com a ajuda do professor, cartazes, avisos, folhetos, regras e regulamentos que organizam a vida na comunidade escolar, dentre outros gêneros do campo da atuação cidadã, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('00cb7875-7649-4fb4-91d5-efe2b2e03ec4'::uuid,'EF12LP11','Escrever, em colaboração com os colegas e com a ajuda do professor, fotolegendas em notícias, manchetes e lides em notícias, álbum de fotos digital noticioso e notícias curtas para público infantil, digitais ou impressos, dentre outros gêneros do campo jornalístico, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('eefade3a-27bb-475d-950b-eef34b379a70'::uuid,'EF12LP12','Escrever, em colaboração com os colegas e com a ajuda do professor, slogans, anúncios publicitários e textos de campanhas de conscientização destinados ao público infantil, dentre outros gêneros do campo publicitário, considerando a situação comunicativa e o tema/ assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7ac8b95a-c020-4750-833f-3f14882c60fa'::uuid,'EF12LP13','Planejar, em colaboração com os colegas e com a ajuda do professor, slogans e peça de campanha de conscientização destinada ao público infantil que possam ser repassados oralmente por meio de ferramentas digitais, em áudio ou vídeo, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('d7967cb7-59ee-44e2-a450-8e6f8a13d222'::uuid,'EF12LP14','Identificar e reproduzir, em fotolegendas de notícias, álbum de fotos digital noticioso, cartas de leitor (revista infantil), digitais ou impressos, a formatação e diagramação específica de cada um desses gêneros, inclusive em suas versões orais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('1513bbb0-290d-4f32-aaa5-420c8a57334a'::uuid,'EF12LP15','Identificar a forma de composição de slogans publicitários.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('9b591691-c325-4011-b577-209a3491fb67'::uuid,'EF12LP16','Identificar e reproduzir, em anúncios publicitários e textos de campanhas de conscientização destinados ao público infantil (orais e escritos, digitais ou impressos), a formatação e diagramação específica de cada um desses gêneros, inclusive o uso de imagens.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c06f3af9-3113-435f-8b94-f94afb6dcaac'::uuid,'EF12LP17','Ler e compreender, em colaboração com os colegas e com a ajuda do professor, enunciados de tarefas escolares, diagramas, curiosidades, pequenos relatos de experimentos, entrevistas, verbetes de enciclopédia infantil, entre outros gêneros do campo investigativo, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('2822dafa-843d-49b4-bdf9-7e1acb573956'::uuid,'EF12LP18','Apreciar poemas e outros textos versificados, observando rimas, sonoridades, jogos de palavras, reconhecendo seu pertencimento ao mundo imaginário e sua dimensão de encantamento, jogo e fruição.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ba1d45d7-0cfd-44ae-ad46-1b199d4c3f22'::uuid,'EF12LP19','Reconhecer, em textos versificados, rimas, sonoridades, jogos de palavras, palavras, expressões, comparações, relacionando-as com sensações e associações.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('14d23425-f6e0-4eb7-bda0-06d565d2c654'::uuid,'EF35LP01','Ler e compreender, silenciosamente e, em seguida, em voz alta, com autonomia e fluência, textos curtos com nível de textualidade adequado.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('28029f60-68e4-4db8-8f6d-942df99310b0'::uuid,'EF35LP02','Selecionar livros da biblioteca e/ou do cantinho de leitura da sala de aula e/ou disponíveis em meios digitais para leitura individual, justificando a escolha e compartilhando com os colegas sua opinião, após a leitura.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('945b4cc5-5bc3-4cb8-b234-2243e298ae24'::uuid,'EF35LP03','Identificar a ideia central do texto, demonstrando compreensão global.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('0471de18-4ec9-437e-bae9-d07a3aa2dd6f'::uuid,'EF35LP04','Inferir informações implícitas nos textos lidos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('023085dc-54c0-465e-b3f7-d142186b8bfe'::uuid,'EF35LP05','Inferir o sentido de palavras ou expressões desconhecidas em textos, com base no contexto da frase ou do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('a68d485a-fce4-4481-8ebb-a10ab054b827'::uuid,'EF35LP06','Recuperar relações entre partes de um texto, identificando substituições lexicais (de substantivos por sinônimos) ou pronominais (uso de pronomes anafóricos – pessoais, possessivos, demonstrativos) que contribuem para a continuidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5a689511-9aa3-4289-a135-8a5dc3b26fe0'::uuid,'EF35LP07','Utilizar, ao produzir um texto, conhecimentos linguísticos e gramaticais, tais como ortografia, regras básicas de concordância nominal e verbal, pontuação (ponto final, ponto de exclamação, ponto de interrogação, vírgulas em enumerações) e pontuação do discurso direto, quando for o caso.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('640f991f-5e43-4b0a-83e1-1e25c6d8fbd0'::uuid,'EF35LP08','Utilizar, ao produzir um texto, recursos de referenciação (por substituição lexical ou por pronomes pessoais, possessivos e demonstrativos), vocabulário apropriado ao gênero, recursos de coesão pronominal (pronomes anafóricos) e articuladores de relações de sentido (tempo, causa, oposição, conclusão, comparação), com nível suficiente de informatividade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('9ce80d3c-a84b-4697-a657-50a9d6179770'::uuid,'EF35LP09','Organizar o texto em unidades de sentido, dividindo-o em parágrafos segundo as normas gráficas e de acordo com as características do gênero textual.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('60afd065-a222-4298-b781-48baafdb4006'::uuid,'EF35LP10','Identificar gêneros do discurso oral, utilizados em diferentes situações e contextos comunicativos, e suas características linguístico- expressivas e composicionais (conversação espontânea, conversação telefônica, entrevistas pessoais, entrevistas no rádio ou na TV, debate, noticiário de rádio e TV, narração de jogos esportivos no rádio e TV, aula, debate etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('4b10c540-4635-47ab-86b1-c02000483558'::uuid,'EF35LP11','Ouvir gravações, canções, textos falados em diferentes variedades linguísticas, identificando características regionais, urbanas e rurais da fala e respeitando as diversas variedades linguísticas como características do uso da língua por diferentes grupos regionais ou diferentes culturas locais, rejeitando preconceitos linguísticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('f18357af-f4f5-49d7-9077-bafe48315df7'::uuid,'EF35LP12','Recorrer ao dicionário para esclarecer dúvida sobre a escrita de palavras, especialmente no caso de palavras com relações irregulares fonema-grafema.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b742e2f1-0ed3-4572-91f8-8fe1aebbbc18'::uuid,'EF35LP13','Memorizar a grafia de palavras de uso frequente nas quais as relações fonema-grafema são irregulares e com h inicial que não representa fonema.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7c76bbba-f382-45cc-8d2e-655ce8e5c501'::uuid,'EF35LP14','Identificar em textos e usar na produção textual pronomes pessoais, possessivos e demonstrativos, como recurso coesivo anafórico.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ee6f03f3-c785-464e-829d-e053c469570e'::uuid,'EF35LP15','Opinar e defender ponto de vista sobre tema polêmico relacionado a situações vivenciadas na escola e/ou na comunidade, utilizando registro formal e estrutura adequada à argumentação, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('0dc9c300-2cd4-4e0c-a1bc-39c603fb4ba4'::uuid,'EF35LP16','Identificar e reproduzir, em notícias, manchetes, lides e corpo de notícias simples para público infantil e cartas de reclamação (revista infantil), digitais ou impressos, a formatação e diagramação específica de cada um desses gêneros, inclusive em suas versões orais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ca6fa10b-1090-4d2d-a77f-69286b951616'::uuid,'EF35LP17','Buscar e selecionar, com o apoio do professor, informações de interesse sobre fenômenos sociais e naturais, em textos que circulam em meios impressos ou digitais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('7c0abb43-ada2-4772-9381-4d327011a13f'::uuid,'EF01LP19','Recitar parlendas, quadras, quadrinhas, trava-línguas, com entonação adequada e observando as rimas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('81d17496-9892-4352-8182-1c88479632a6'::uuid,'EF35LP18','Escutar, com atenção, apresentações de trabalhos realizadas por colegas, formulando perguntas pertinentes ao tema e solicitando esclarecimentos sempre que necessário.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('71433bfb-056c-4852-b160-3e1e1144c723'::uuid,'EF35LP19','Recuperar as ideias principais em situações formais de escuta de exposições, apresentações e palestras.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b7096d90-6fda-4581-8e7e-e90d21381e32'::uuid,'EF35LP20','Expor trabalhos ou pesquisas escolares, em sala de aula, com apoio de recursos multissemióticos (imagens, diagrama, tabelas etc.), orientando-se por roteiro escrito, planejando o tempo de fala e adequando a linguagem à situação comunicativa.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c318ebc9-5235-460b-9854-73eb2f6e4880'::uuid,'EF35LP21','Ler e compreender, de forma autônoma, textos literários de diferentes gêneros e extensões, inclusive aqueles sem ilustrações, estabelecendo preferências por gêneros, temas, autores.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('58d5f369-eca8-4656-9a12-681ea743f9ae'::uuid,'EF35LP22','Perceber diálogos em textos narrativos, observando o efeito de sentido de verbos de enunciação e, se for o caso, o uso de variedades linguísticas no discurso direto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e40bf9e5-3254-4132-8f85-fef4003b5776'::uuid,'EF35LP23','Apreciar poemas e outros textos versificados, observando rimas, aliterações e diferentes modos de divisão dos versos, estrofes e refrões e seu efeito de sentido.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('9fdcb92d-167d-4f5f-b32d-563b3dfcfc02'::uuid,'EF35LP24','Identificar funções do texto dramático (escrito para ser encenado) e sua organização por meio de diálogos entre personagens e marcadores das falas das personagens e das cenas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('baa068c6-75a1-49eb-9378-b40900b5ce44'::uuid,'EF35LP25','Criar narrativas ficcionais, com certa autonomia, utilizando detalhes descritivos, sequências de eventos e imagens apropriadas para sustentar o sentido do texto, e marcadores de tempo, espaço e de fala de personagens.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('5187fc64-033c-402f-8688-aede351bb443'::uuid,'EF35LP26','Ler e compreender, com certa autonomia, narrativas ficcionais que apresentem cenários e personagens, observando os elementos da estrutura narrativa: enredo, tempo, espaço, personagens, narrador e a construção do discurso indireto e discurso direto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('10306f74-9008-4087-b9fb-4f6cc961d06c'::uuid,'EF35LP27','Ler e compreender, com certa autonomia, textos em versos, explorando rimas, sons e jogos de palavras, imagens poéticas (sentidos figurados) e recursos visuais e sonoros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ec8a135d-ba3e-4db6-921e-33dd2592f7bd'::uuid,'EF35LP28','Declamar poemas, com entonação, postura e interpretação adequadas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('bf1519ce-794f-40cd-8e04-4cbb6941d1af'::uuid,'EF35LP29','Identificar, em narrativas, cenário, personagem central, conflito gerador, resolução e o ponto de vista com base no qual histórias são narradas, diferenciando narrativas em primeira e terceira pessoas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('a3061b3f-7867-4176-b71e-3dbb51e60932'::uuid,'EF35LP30','Diferenciar discurso indireto e discurso direto, determinando o efeito de sentido de verbos de enunciação e explicando o uso de variedades linguísticas no discurso direto, quando for o caso.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('234e9195-cc1b-4699-974d-c33800613e56'::uuid,'EF35LP31','Identificar, em textos versificados, efeitos de sentido decorrentes do uso de recursos rítmicos e sonoros e de metáforas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('566ea8a5-6af2-494b-a152-92738a9500ad'::uuid,'EF01LP02','Escrever, espontaneamente ou por ditado, palavras e frases de forma alfabética – usando letras/grafemas que representem fonemas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('e6317ed6-a47e-4d07-bf6e-71acd7a48e48'::uuid,'EF01LP03','Observar escritas convencionais, comparando-as às suas produções escritas, percebendo semelhanças e diferenças.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('254d9bb6-c965-4e62-853d-d7abd75b97b4'::uuid,'EF01LP04','Distinguir as letras do alfabeto de outros sinais gráficos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('e21bd731-a7dc-4c41-8288-b6f5d8b81890'::uuid,'EF01LP05','Reconhecer o sistema de escrita alfabética como representação dos sons da fala.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('bf76e1c5-2602-40d6-a996-4d049dde1a7d'::uuid,'EF01LP06','Segmentar oralmente palavras em sílabas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('1acab380-d68b-4962-bed6-f65d8e7e2470'::uuid,'EF01LP07','Identificar fonemas e sua representação por letras.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('c2d10e38-4db0-4a3e-b9f6-9da6b09681c6'::uuid,'EF01LP08','Relacionar elementos sonoros (sílabas, fonemas, partes de palavras) com sua representação escrita.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('0331731e-00b0-4315-b30c-7390682163eb'::uuid,'EF01LP09','Comparar palavras, identificando semelhanças e diferenças entre sons de sílabas iniciais, mediais e finais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('ffa4c821-5d39-406b-9e32-8ac62bd2f532'::uuid,'EF01LP10','Nomear as letras do alfabeto e recitá-lo na ordem das letras.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('33e2ff28-d94c-4f58-a06e-944b5e41e584'::uuid,'EF01LP11','Conhecer, diferenciar e relacionar letras em formato imprensa e cursiva, maiúsculas e minúsculas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('6009e244-04bb-43be-bffa-ce4eead9422f'::uuid,'EF01LP12','Reconhecer a separação das palavras, na escrita, por espaços em branco.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('1c4eab23-e4c8-4d4c-b9f5-a60fd5881856'::uuid,'EF01LP13','Comparar palavras, identificando semelhanças e diferenças entre sons de sílabas iniciais, mediais e finais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('a0878a3b-60bc-41f6-b9fe-998e07ac4f33'::uuid,'EF01LP14','Identificar outros sinais no texto além das letras, como pontos finais, de interrogação e exclamação, número e seus efeitos na entonação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('a49fff9b-e357-4f7b-8cd6-e216cda685d0'::uuid,'EF01LP15','Agrupar palavras pelo critério de aproximação de significado (sinonímia) e separar palavras pelo critério de oposição de significado (antonímia).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('ad0895c1-9922-480f-a85e-2528c534aa71'::uuid,'EF01LP16','Ler e compreender, em colaboração com os colegas e com a ajuda do professor, quadras, quadrinhas, parlendas, trava-línguas, dentre outros gêneros do campo da vida cotidiana, considerando a situação comunicativa e o tema/assunto do texto e relacionando sua forma de organização à sua finalidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('64f0aa49-4f96-42da-830d-19bc9a97a968'::uuid,'EF01LP17','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, listas, agendas, calendários, avisos, convites, receitas, instruções de montagem e legendas para álbuns, fotos ou ilustrações (digitais ou impressos), dentre outros gêneros do campo da vida cotidiana, considerando a situação comunicativa e o tema/assunto/ finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('b91573f1-c488-400a-aecd-09e9c0610d71'::uuid,'EF01LP18','Registrar, em colaboração com os colegas e com a ajuda do professor, cantigas, quadras, quadrinhas, parlendas, trava-línguas, dentre outros gêneros do campo da vida cotidiana, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('5c16a9de-b886-45f0-ba9b-5d3ac3420c4b'::uuid,'EF01LP20','Identificar e reproduzir, em listas, agendas, calendários, regras, avisos, convites, receitas, instruções de montagem e legendas para álbuns, fotos ou ilustrações (digitais ou impressos), a formatação e diagramação específica de cada um desses gêneros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('6c7402cc-47e8-4b8b-b1e4-03157c709689'::uuid,'EF01LP21','Escrever, em colaboração com os colegas e com a ajuda do professor, listas de regras e regulamentos que organizam a vida na comunidade escolar, dentre outros gêneros do campo da atuação cidadã, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('75b37f33-e92a-4db7-b500-ba4af6c0770e'::uuid,'EF01LP24','Identificar e reproduzir, em enunciados de tarefas escolares, diagramas, entrevistas, curiosidades, digitais ou impressos, a formatação e diagramação específica de cada um desses gêneros, inclusive em suas versões orais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('e6cdf454-3a11-4375-8af7-76ad2caddde8'::uuid,'EF01LP25','Produzir, tendo o professor como escriba, recontagens de histórias lidas pelo professor, histórias imaginadas ou baseadas em livros de imagens, observando a forma de composição de textos narrativos (personagens, enredo, tempo e espaço).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('e1b37353-0e1f-46fa-a42a-9a906e64dc05'::uuid,'EF01LP26','Identificar elementos de uma narrativa lida ou escutada, incluindo personagens, enredo, tempo e espaço.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('ebd755b2-610c-46db-bdfa-b05835888f2e'::uuid,'D1','Localizar informações explícitas em um texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('420e6fc6-2467-4397-9c36-40463af8535d'::uuid,'D3','Inferir o sentido de uma palavra ou expressão.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('9d0aa133-90db-4eb9-82bc-5debc2488143'::uuid,'D4','Inferir uma informação implícita em um texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('71f5a405-451e-4c6c-a638-37671e58efc9'::uuid,'D6','Identificar o tema de um texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('3426cc37-72ee-4c98-830c-ca5131965dd3'::uuid,'D11','Distinguir um fato da opinião relativa a esse fato.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('dd26b695-cd5c-4743-b38b-6e2b7b62aa37'::uuid,'D5','Interpretar texto com auxílio de material gráfico diverso (propagandas, quadrinhos, foto, etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('af08e6a1-73f3-4649-83db-ae0f2ca1babd'::uuid,'D9','Identificar a finalidade de textos de diferentes gêneros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('6771073b-ca24-4db1-b6ba-996751e91eb5'::uuid,'D15','Reconhecer diferentes formas de tratar uma informação na comparação de textos que tratam do mesmo tema, em função das condições em que ele foi produzido e daquelas em que será recebido.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('71b0a910-5265-46ac-9a77-8e435d9e25ca'::uuid,'D2','Estabelecer relações entre partes de um texto, identificando repetições ou substituições que contribuem para a continuidade de um texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('d3e092c9-9a80-4cf7-9255-60c42bee9f64'::uuid,'D7','Identificar o conflito gerador do enredo e os elementos que constroem a narrativa.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('3a53eb4f-23cf-47e1-a374-b37e7464e595'::uuid,'D8','Estabelecer relação causa /consequência entre partes e elementos do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('04940acc-1e01-4274-9a54-bec278dd1566'::uuid,'D12','Estabelecer relações lógico-discursivas presentes no texto, marcadas por conjunções, advérbios, etc.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('382cba0e-6238-4411-a8f3-325027e6eda1'::uuid,'D13','Identificar efeitos de ironia ou humor em textos variados.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('7ef17f7a-067a-45f8-b3d1-06644cc0a899'::uuid,'D14','Identificar o efeito de sentido decorrente do uso da pontuação e de outras notações.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('47875d53-de89-4b56-97a4-da635629f0ca'::uuid,'D10','Identificar as marcas linguísticas que evidenciam o locutor e o interlocutor de um texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','391ed6e8-fc45-46f8-8e4c-065005d2329f'::uuid),
	 ('78c128a3-29db-458e-83c8-95daa32188ba'::uuid,'EF02LP03','Ler e escrever palavras com correspondências regulares diretas entre letras e fonemas (f, v, t, d, p, b) e correspondências regulares contextuais (c e q; e e o, em posição átona em final de palavra).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('9831ca81-4edf-4d43-b6af-b427c299f902'::uuid,'EF02LP05','Ler e escrever corretamente palavras com marcas de nasalidade (til, m, n).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('d4318da1-6fa6-419e-a15f-300103fcd8bf'::uuid,'EF02LP06','Perceber o princípio acrofônico que opera nos nomes das letras do alfabeto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('ef0443b2-3196-457f-8cd0-a2dfa75a4e98'::uuid,'EF02LP07','Escrever palavras, frases, textos curtos nas formas imprensa e cursiva.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('9d055484-567d-4bac-96b7-4566b13185c7'::uuid,'EF02LP08','Segmentar corretamente as palavras ao escrever frases e textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a6d5ac4a-93e3-43bc-863b-3645ef461c50'::uuid,'EF02LP09','Usar adequadamente ponto final, ponto de interrogação e ponto de exclamação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('d7160e2f-abf6-4486-9995-9d316f110bc1'::uuid,'EF02LP10','Identificar sinônimos de palavras de texto lido, determinando a diferença de sentido entre eles, e formar antônimos de palavras encontradas em texto lido pelo acréscimo do prefixo de negação in-/im-.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('b255c4b1-f2fe-4569-b695-434ba2715838'::uuid,'EF02LP11','Formar o aumentativo e o diminutivo de palavras com os sufixos -ão e -inho/-zinho.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a3de4323-1677-43e9-b1ab-31d3b88aa579'::uuid,'EF02LP12','Ler e compreender com certa autonomia cantigas, letras de canção, dentre outros gêneros do campo da vida cotidiana, considerando a situação comunicativa e o tema/assunto do texto e relacionando sua forma de organização à sua finalidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('d8feba67-dcb6-42f5-92ed-a7c0434b5dd5'::uuid,'EF02LP13','Planejar e produzir bilhetes e cartas, em meio impresso e/ou digital, dentre outros gêneros do campo da vida cotidiana, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('4dc951c6-b018-4e71-b15e-e49cc8861f10'::uuid,'EF02LP14','Planejar e produzir pequenos relatos de observação de processos, de fatos, de experiências pessoais, mantendo as características do gênero, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('a7b10327-772d-4c9d-b9f8-3f8cae6497c1'::uuid,'EF02LP16','Identificar e reproduzir, em bilhetes, recados, avisos, cartas, e- mails, receitas (modo de fazer), relatos (digitais ou impressos), a formatação e diagramação específica de cada um desses gêneros.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('00409773-44e5-4d62-8e9c-139fa004bfcb'::uuid,'EF02LP17','Identificar e reproduzir, em relatos de experiências pessoais, a sequência dos fatos, utilizando expressões que marquem a passagem do tempo ("antes", "depois", "ontem", "hoje", "amanhã", "outro dia", "antigamente", "há muito tempo" etc.), e o nível de informatividade necessário.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('39339ff6-d98c-4a95-aa62-c93a17c6e82d'::uuid,'5A2.2','Analisar os efeitos de sentido de verbos de enunciação.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('5201e422-b9e7-4acf-aa06-f19e177e2fdb'::uuid,'EF02LP18','Planejar e produzir cartazes e folhetos para divulgar eventos da escola ou da comunidade, utilizando linguagem persuasiva e elementos textuais e visuais (tamanho da letra, leiaute, imagens) adequados ao gênero, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('ec5a81fd-a3a5-45a6-86b3-6a5ecfda18ef'::uuid,'EF02LP19','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, notícias curtas para público infantil, para compor jornal falado que possa ser repassado oralmente ou em meio digital, em áudio ou vídeo, dentre outros gêneros do campo jornalístico, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('8116dbe0-d9d2-49d2-a8bf-38eef84d8a5d'::uuid,'EF02LP20','Reconhecer a função de textos utilizados para apresentar informações coletadas em atividades de pesquisa (enquetes, pequenas entrevistas, registros de experimentações).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('7a7137e8-3439-4be8-bb9d-b9d3f4c2e820'::uuid,'EF02LP21','Explorar, com a mediação do professor, textos informativos de diferentes ambientes digitais de pesquisa, conhecendo suas possibilidades.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('00a2f46e-1da5-47df-a533-c226ed7277ab'::uuid,'EF02LP22','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, pequenos relatos de experimentos, entrevistas, verbetes de enciclopédia infantil, dentre outros gêneros do campo investigativo, digitais ou impressos, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('0961f5b4-5b08-4022-9f6c-36bab870d37f'::uuid,'EF02LP23','Planejar e produzir, com certa autonomia, pequenos registros de observação de resultados de pesquisa, coerentes com um tema investigado.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('35d9d2f7-d790-4cea-8ce8-d7623dc6d926'::uuid,'EF02LP24','Planejar e produzir, em colaboração com os colegas e com a ajuda do professor, relatos de experimentos, registros de observação, entrevistas, dentre outros gêneros do campo investigativo, que possam ser repassados oralmente por meio de ferramentas digitais, em áudio ou vídeo, considerando a situação comunicativa e o tema/assunto/ finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('421dda4f-7e94-4f2e-bd20-a90a42435d01'::uuid,'EF02LP25','Identificar e reproduzir, em relatos de experimentos, entrevistas, verbetes de enciclopédia infantil, digitais ou impressos, a formatação e diagramação específica de cada um desses gêneros, inclusive em suas versões orais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('90cabaae-0556-41ec-8b91-e9ac2fec84ca'::uuid,'EF02LP26','Ler e compreender, com certa autonomia, textos literários, de gêneros variados, desenvolvendo o gosto pela leitura.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('ff0030cc-48e6-4217-a856-f4fcdb053032'::uuid,'EF02LP27','Reescrever textos narrativos literários lidos pelo professor.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('19623fe7-4239-4d28-b456-5f6957f18a31'::uuid,'EF02LP28','Reconhecer o conflito gerador de uma narrativa ficcional e sua resolução, além de palavras, expressões e frases que caracterizam personagens e ambientes.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid),
	 ('9c684aeb-0a7c-4779-bf46-6a20b5695324'::uuid,'EF02LP29','Observar, em poemas visuais, o formato do texto na página, as ilustrações e outros efeitos visuais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','74821122-e632-4301-b6f5-42b92b802a55'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('95fe30d1-afd5-460c-a650-a5f3516380fe'::uuid,'EF03LP01','Ler e escrever palavras com correspondências regulares contextuais entre grafemas e fonemas – c/qu; g/gu; r/rr; s/ss; o (e não u) e e (e não i) em sílaba átona em final de palavra – e com marcas de nasalidade (til, m, n).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('ed4de969-8bd8-4796-a5da-5eb49163ba15'::uuid,'EF03LP02','Ler e escrever corretamente palavras com sílabas CV, V, CVC, CCV, VC, VV, CVV, identificando que existem vogais em todas as sílabas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('5108e78b-059e-460d-9c77-784bb316ec51'::uuid,'EF03LP03','Ler e escrever corretamente palavras com os dígrafos lh, nh, ch.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('77b804f3-99a8-487e-a235-04fbb8b16f3a'::uuid,'EF03LP04','Usar acento gráfico (agudo ou circunflexo) em monossílabos tônicos terminados em a, e, o e em palavras oxítonas terminadas em a, e, o, seguidas ou não de s.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('8df34e24-7a21-48d7-8886-26db0abbce2a'::uuid,'EF03LP05','Identificar o número de sílabas de palavras, classificando-as em monossílabas, dissílabas, trissílabas e polissílabas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('8e85fad1-7bbe-4a7e-9526-db6fa2e2a19c'::uuid,'EF03LP06','Identificar a sílaba tônica em palavras, classificando-as em oxítonas, paroxítonas e proparoxítonas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('ccdfb902-672b-4f49-82f9-6540aea2fda7'::uuid,'EF03LP07','Identificar a função na leitura e usar na escrita ponto final, ponto de interrogação, ponto de exclamação e, em diálogos (discurso direto), dois- pontos e travessão.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('b6b76c9a-c836-4b63-9a53-5540a931ee64'::uuid,'EF03LP08','Identificar e diferenciar, em textos, substantivos e verbos e suas funções na oração: agente, ação, objeto da ação.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('db2c4493-e976-4bf8-b4c2-cc35d2ebf8dd'::uuid,'EF03LP09','Identificar, em textos, adjetivos e sua função de atribuição de propriedades aos substantivos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('52846e58-209e-40ff-b270-cc9025940780'::uuid,'EF03LP10','Reconhecer prefixos e sufixos produtivos na formação de palavras derivadas de substantivos, de adjetivos e de verbos, utilizando-os para compreender palavras e para formar novas palavras.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('c133b137-e24f-4a32-854e-40637ecd14de'::uuid,'EF03LP11','Ler e compreender, com autonomia, textos injuntivos instrucionais (receitas, instruções de montagem etc.), com a estrutura própria desses textos (verbos imperativos, indicação de passos a ser seguidos) e mesclando palavras, imagens e recursos gráfico- visuais, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('9e50a769-3bde-42ea-af38-c0646f892f58'::uuid,'EF03LP12','Ler e compreender, com autonomia, cartas pessoais e diários, com expressão de sentimentos e opiniões, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero carta e considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('003e9735-0884-43f5-9c59-8817c3200786'::uuid,'EF03LP13','Planejar e produzir cartas pessoais e diários, com expressão de sentimentos e opiniões, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções dos gêneros carta e diário e considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('ef1e904b-0302-4db9-869a-fbdd63934086'::uuid,'EF03LP14','Planejar e produzir textos injuntivos instrucionais, com a estrutura própria desses textos (verbos imperativos, indicação de passos a ser seguidos) e mesclando palavras, imagens e recursos gráfico-visuais, considerando a situação comunicativa e o tema/ assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('e811ba85-122c-417c-87bc-f5cf852cbf2e'::uuid,'5A2.4','Analisar os efeitos de sentido decorrentes do uso dos advérbios.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('82adc2a3-595e-4fda-a171-8e509482b84e'::uuid,'EF03LP16','Identificar e reproduzir, em textos injuntivos instrucionais (receitas, instruções de montagem, digitais ou impressos), a formatação própria desses textos (verbos imperativos, indicação de passos a ser seguidos) e a diagramação específica dos textos desses gêneros (lista de ingredientes ou materiais e instruções de execução – \"modo de fazer\").','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('56f26fdc-9173-4461-809f-9609ee625aee'::uuid,'EF03LP17','Identificar e reproduzir, em gêneros epistolares e diários, a formatação própria desses textos (relatos de acontecimentos, expressão de vivências, emoções, opiniões ou críticas) e a diagramação específica dos textos desses gêneros (data, saudação, corpo do texto, despedida, assinatura).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('84c57ed9-8a6d-41a6-b069-403c24c5536d'::uuid,'EF03LP18','Ler e compreender, com autonomia, cartas dirigidas a veículos da mídia impressa ou digital (cartas de leitor e de reclamação a jornais, revistas) e notícias, dentre outros gêneros do campo jornalístico, de acordo com as convenções do gênero carta e considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('a9044dd0-52c0-4f56-a793-7000bbc23939'::uuid,'EF03LP19','Identificar e discutir o propósito do uso de recursos de persuasão (cores, imagens, escolha de palavras, jogo de palavras, tamanho de letras) em textos publicitários e de propaganda, como elementos de convencimento.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('d57bc77a-205d-4337-be02-284e8800ee55'::uuid,'EF03LP20','Produzir cartas dirigidas a veículos da mídia impressa ou digital (cartas do leitor ou de reclamação a jornais ou revistas), dentre outros gêneros do campo político- cidadão, com opiniões e críticas, de acordo com as convenções do gênero carta e considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('2eaf3e99-fc51-4ce1-b168-94057f415ed9'::uuid,'EF03LP21','Produzir anúncios publicitários, textos de campanhas de conscientização destinados ao público infantil, observando os recursos de persuasão utilizados nos textos publicitários e de propaganda (cores, imagens, slogan, escolha de palavras, jogo de palavras, tamanho e tipo de letras, diagramação).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('27b3339f-2b74-43fb-92b0-f52826e5da12'::uuid,'EF03LP22','Planejar e produzir, em colaboração com os colegas, telejornal para público infantil com algumas notícias e textos de campanhas que possam ser repassados oralmente ou em meio digital, em áudio ou vídeo, considerando a situação comunicativa, a organização específica da fala nesses gêneros e o tema/assunto/ finalidade dos textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('28ca763f-572d-4959-afdc-ae5430715a3c'::uuid,'EF03LP23','Analisar o uso de adjetivos em cartas dirigidas a veículos da mídia impressa ou digital (cartas do leitor ou de reclamação a jornais ou revistas), digitais ou impressas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('9c7093ca-7b2a-43b4-ab21-490505ecf055'::uuid,'EF03LP24','Ler/ouvir e compreender, com autonomia, relatos de observações e de pesquisas em fontes de informações, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('b01a2e7f-f0ce-402e-953e-c7b42744190d'::uuid,'EF03LP25','Planejar e produzir textos para apresentar resultados de observações e de pesquisas em fontes de informações, incluindo, quando pertinente, imagens, diagramas e gráficos ou tabelas simples, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('95ca0a02-3d6c-465c-b9f5-b97c20ca4f17'::uuid,'EF03LP26','Identificar e reproduzir, em relatórios de observação e pesquisa, a formatação e diagramação específica desses gêneros (passos ou listas de itens, tabelas, ilustrações, gráficos, resumo dos resultados), inclusive em suas versões orais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('ae9dc576-d836-4f1e-8666-02b1f9eceda3'::uuid,'EF03LP27','Recitar cordel e cantar repentes e emboladas, observando as rimas e obedecendo ao ritmo e à melodia.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','ea1ed64b-c9f5-4156-93b2-497ecf9e0d84'::uuid),
	 ('e23ebdb5-7c00-4d11-8851-2520e173de99'::uuid,'EF04LP01','Grafar palavras utilizando regras de correspondência fonema--grafema regulares diretas e contextuais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('b73fbcfe-49bb-4385-8dd8-b601c4a26247'::uuid,'EF04LP02','Leitura e escrita, corretamente, palavras com sílabas VV e CVV em casos nos quais a combinação VV (ditongo) é reduzida na língua oral (ai, ei, ou).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('c2aa03d1-923d-4271-99f9-ecdc598227a4'::uuid,'EF04LP03','Localizar palavras no dicionário para esclarecer significados, reconhecendo o significado mais plausível para o contexto que deu origem à consulta.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('fa1f0453-0ea1-453e-840a-f98f519d67b9'::uuid,'EF04LP04','Usar acento gráfico (agudo ou circunflexo) em paroxítonas terminadas em -i(s), -l, -r, - ão(s).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('e4c1df09-bf73-4e2b-888c-ca90410454cb'::uuid,'EF04LP05','Identificar a função na leitura e usar, adequadamente, na escrita ponto final, de interrogação, de exclamação, dois- pontos e travessão em diálogos (discurso direto), vírgula em enumerações e em separação de vocativo e de aposto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('5534d288-5072-4419-bdf2-2692f1fd744b'::uuid,'EF04LP06','Identificar em textos e usar na produção textual a concordância entre substantivo ou pronome pessoal e verbo (concordância verbal).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('e662967c-f01c-4b08-8294-949dec37eaec'::uuid,'EF04LP07','Identificar em textos e usar na produção textual a concordância entre artigo, substantivo e adjetivo (concordância no grupo nominal).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('504be440-4292-41b5-95d2-830c049746f2'::uuid,'EF04LP08','Reconhecer e grafar, corretamente, palavras derivadas com os sufixos -agem, -oso, -eza, - izar/-isar (regulares morfológicas).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('f20e79da-b49f-47ee-a1b7-6b87efe0ea13'::uuid,'EF04LP09','Ler e compreender, com autonomia, boletos, faturas e carnês, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero (campos, itens elencados, medidas de consumo, código de barras) e considerando a situação comunicativa e a finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('892cb977-3d58-46c2-9c39-d47cdf5519a9'::uuid,'EF04LP10','Ler e compreender, com autonomia, cartas pessoais de reclamação, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero carta e considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('db9d8abe-88db-44fc-b355-9cd160410795'::uuid,'EF04LP11','Planejar e produzir, com autonomia, cartas pessoais de reclamação, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero carta e com a estrutura própria desses textos (problema, opinião, argumentos), considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('ee455c7b-34bf-4434-9475-0a77ecf8e7c6'::uuid,'EF04LP12','Assistir, em vídeo digital, a programa infantil com instruções de montagem, de jogos e brincadeiras e, a partir dele, planejar e produzir tutoriais em áudio ou vídeo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('2305981e-cfcb-41da-8acd-42c4a830f2a6'::uuid,'EF04LP13','Identificar e reproduzir, em textos injuntivos instrucionais (instruções de jogos digitais ou impressos), a formatação própria desses textos (verbos imperativos, indicação de passos a ser seguidos) e formato específico dos textos orais ou escritos desses gêneros (lista/ apresentação de materiais e instruções/passos de jogo).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('00e5df18-69c9-4cde-83a4-ce094ead935b'::uuid,'EF04LP14','Identificar, em notícias, fatos, participantes, local e momento/tempo da ocorrência do fato noticiado.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('30ae7d7d-8d7c-4dab-992d-3d6e3bec1175'::uuid,'EF04LP15','Distinguir fatos de opiniões/sugestões em textos (informativos, jornalísticos, publicitários etc.).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('ab696adf-3f40-4804-9161-2b4ea85d3ed6'::uuid,'EF04LP16','Produzir notícias sobre fatos ocorridos no universo escolar, digitais ou impressas, para o jornal da escola, noticiando os fatos e seus atores e comentando decorrências, de acordo com as convenções do gênero notícia e considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('839630ff-568f-4d01-9e82-70f74f117302'::uuid,'EF04LP17','Produzir jornais radiofônicos ou televisivos e entrevistas veiculadas em rádio, TV e na internet, orientando-se por roteiro ou texto e demonstrando conhecimento dos gêneros jornal falado/televisivo e entrevista.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('9e1cedbc-b3a3-4c93-930c-0b2729532929'::uuid,'EF04LP18','Analisar o padrão entonacional e a expressão facial e corporal de âncoras de jornais radiofônicos ou televisivos e de entrevistadores/entrevistados.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('55aaafe3-65b5-40c4-8f8d-930973f61877'::uuid,'EF04LP19','Ler e compreender textos expositivos de divulgação científica para crianças, considerando a situação comunicativa e o tema/ assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('e2ceca13-fad5-42bf-a77e-a046fda48e8f'::uuid,'EF04LP20','Reconhecer a função de gráficos, diagramas e tabelas em textos, como forma de apresentação de dados e informações.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('90a7148b-ede6-4653-9364-df80c97b5b7a'::uuid,'EF04LP21','Planejar e produzir textos sobre temas de interesse, com base em resultados de observações e pesquisas em fontes de informações impressas ou eletrônicas, incluindo, quando pertinente, imagens e gráficos ou tabelas simples, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('f1d0bf92-5e31-4b00-bb1a-9089f231dbdd'::uuid,'EF04LP22','Planejar e produzir, com certa autonomia, verbetes de enciclopédia infantil, digitais ou impressos, considerando a situação comunicativa e o tema/ assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('0fdc37cb-451b-46f5-bac1-8223c52a1b22'::uuid,'EF04LP23','Identificar e reproduzir, em verbetes de enciclopédia infantil, digitais ou impressos, a formatação e diagramação específica desse gênero (título do verbete, definição, detalhamento, curiosidades), considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('304ef854-a742-4348-b980-3e81e63b730f'::uuid,'EF04LP24','Identificar e reproduzir, em seu formato, tabelas, diagramas e gráficos em relatórios de observação e pesquisa, como forma de apresentação de dados e informações.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('916e2c5f-4507-4106-86c8-a9f5942efac9'::uuid,'EF04LP25','Planejar e produzir, com certa autonomia, verbetes de dicionário, digitais ou impressos, considerando a situação comunicativa e o tema/assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('5dbbe441-a52c-42df-9c6a-4318367cfec1'::uuid,'EF04LP26','Observar, em poemas concretos, o formato, a distribuição e a diagramação das letras do texto na página.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('7f7d74be-ff35-4d76-b816-f2ce6d442e6e'::uuid,'EF04LP27','Identificar, em textos dramáticos, marcadores das falas das personagens e de cena.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','b8cdea4d-22fe-4647-a9f3-c575eb82c514'::uuid),
	 ('773b1d5a-79e9-4b17-a510-cf0f28c27f7b'::uuid,'EF05LP01','Grafar palavras utilizando regras de correspondência fonema-grafema regulares, contextuais e morfológicas e palavras de uso frequente com correspondências irregulares.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('c8a79e66-12b8-4f1e-993d-7e978b16edf0'::uuid,'EF05LP02','Identificar o caráter polissêmico das palavras (uma mesma palavra com diferentes significados, de acordo com o contexto de uso), comparando o significado de determinados termos utilizados nas áreas científicas com esses mesmos termos utilizados na linguagem usual.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('bea3560a-ee5f-472d-94b6-66024559188d'::uuid,'EF05LP04','Diferenciar, na leitura de textos, vírgula, ponto e vírgula, dois-pontos e reconhecer, na leitura de textos, o efeito de sentido que decorre do uso de reticências, aspas, parênteses.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('024d0a6a-c3e3-4529-8aea-6d5cbf7fb9c7'::uuid,'EF05LP05','Identificar a expressão de presente, passado e futuro em tempos verbais do modo indicativo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('f9e56350-deaf-4f01-a6a2-48b988e0a5a4'::uuid,'EF05LP06','Flexionar, adequadamente, na escrita e na oralidade, os verbos em concordância com pronomes pessoais/nomes sujeitos da oração.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('d55f6a02-6dcc-4810-8dc7-b7dd493c3325'::uuid,'EF05LP07','Identificar, em textos, o uso de conjunções e a relação que estabelecem entre partes do texto: adição, oposição, tempo, causa, condição, finalidade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('5daaaf8a-4cd4-4787-b925-62561ad982c6'::uuid,'EF05LP08','Diferenciar palavras primitivas, derivadas e compostas, e derivadas por adição de prefixo e de sufixo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('c4bca0d1-6095-4d6d-afe0-cc733a7ad1f4'::uuid,'EF05LP09','Ler e compreender, com autonomia, textos instrucionais de regras de jogo, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero e considerando a situação comunicativa e a finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('930a880b-61d7-4519-ae99-58bcac8e1d39'::uuid,'EF05LP10','Ler e compreender, com autonomia, anedotas, piadas e cartuns, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero e considerando a situação comunicativa e a finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('c7844ba7-153e-42b0-9bcb-bec35497ae58'::uuid,'EF05LP11','Registrar, com autonomia, anedotas, piadas e cartuns, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero e considerando a situação comunicativa e a finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('a9d786a8-271b-4571-825a-a400b7b4b4aa'::uuid,'EF05LP12','Planejar e produzir, com autonomia, textos instrucionais de regras de jogo, dentre outros gêneros do campo da vida cotidiana, de acordo com as convenções do gênero e considerando a situação comunicativa e a finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('3dea7108-2000-412d-95d5-d2f65a20c97a'::uuid,'EF05LP13','Assistir, em vídeo digital, a postagem de vlog infantil de críticas de brinquedos e livros de literatura infantil e, a partir dele, planejar e produzir resenhas digitais em áudio ou vídeo.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('87094a84-1141-4be0-bd5b-4e6c3713d1a1'::uuid,'5A3.1','Julgar a eficácia de argumentos em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('bd03a4fc-6592-4438-bc04-d4185088e40e'::uuid,'EF05LP14','Identificar e reproduzir, em textos de resenha crítica de brinquedos ou livros de literatura infantil, a formatação própria desses textos (apresentação e avaliação do produto).','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('5d39f087-a3e0-4341-8406-84b36d796721'::uuid,'EF05LP15','Ler/assistir e compreender, com autonomia, notícias, reportagens, vídeos em vlogs argumentativos, dentre outros gêneros do campo político-cidadão, de acordo com as convenções dos gêneros e considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('b118266f-5160-49ec-8211-acf30eee22d6'::uuid,'EF05LP16','Comparar informações sobre um mesmo fato veiculadas em diferentes mídias e concluir sobre qual é mais confiável e por quê.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('58ac589e-6531-4814-bf52-dc4b0d6dd8f7'::uuid,'EF05LP17','Produzir roteiro para edição de uma reportagem digital sobre temas de interesse da turma, a partir de buscas de informações, imagens, áudios e vídeos na internet, de acordo com as convenções do gênero e considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('f0b3d996-5398-4e34-aeae-36cdbb354573'::uuid,'EF05LP18','Roteirizar, produzir e editar vídeo para vlogs argumentativos sobre produtos de mídia para público infantil (filmes, desenhos animados, HQs, games etc.), com base em conhecimentos sobre os mesmos, de acordo com as convenções do gênero e considerando a situação comunicativa e o tema/ assunto/finalidade do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('15ef10fd-8ba3-41a3-a4cd-c43f97349ddf'::uuid,'EF05LP19','Argumentar oralmente sobre acontecimentos de interesse social, com base em conhecimentos sobre fatos divulgados em TV, rádio, mídia impressa e digital, respeitando pontos de vista diferentes.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('30ce28d7-959c-4e29-9043-6a5b5ee3c6b2'::uuid,'EF05LP20','Analisar a validade e força de argumentos em argumentações sobre produtos de mídia para público infantil (filmes, desenhos animados, HQs, games etc.), com base em conhecimentos sobre os mesmos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('32810e28-2fe1-45cc-8bf5-d9454ec4b5ec'::uuid,'EF05LP21','Analisar o padrão entonacional, a expressão facial e corporal e as escolhas de variedade e registro linguísticos de vloggers de vlogs opinativos ou argumentativos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('658fa650-ed3f-4fb4-9b1c-de24e808793c'::uuid,'EF05LP22','Ler e compreender verbetes de dicionário, identificando a estrutura, as informações gramaticais (significado de abreviaturas) e as informações semânticas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('39fcb951-2290-4b48-99b4-420ac5933320'::uuid,'EF05LP23','Comparar informações apresentadas em gráficos ou tabelas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('7ba1be76-3b95-43a4-a754-a4be0ce38ac0'::uuid,'EF05LP24','Planejar e produzir texto sobre tema de interesse, organizando resultados de pesquisa em fontes de informação impressas ou digitais, incluindo imagens e gráficos ou tabelas, considerando a situação comunicativa e o tema/assunto do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('76855a1f-ae24-48bf-92c1-2ee87061c47d'::uuid,'EF05LP25','Representar cenas de textos dramáticos, reproduzindo as falas das personagens, de acordo com as rubricas de interpretação e movimento indicadas pelo autor.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('180ea9c4-8d10-441f-bdde-b9b41a1e1264'::uuid,'EF05LP26','Utilizar, ao produzir o texto, conhecimentos linguísticos e gramaticais: regras sintáticas de concordância nominal e verbal, convenções de escrita de citações, pontuação (ponto final, dois-pontos, vírgulas em enumerações) e regras ortográficas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('4ac9205e-f565-47b6-aabd-42745934d8af'::uuid,'EF05LP27','Utilizar, ao produzir o texto, recursos de coesão pronominal (pronomes anafóricos) e articuladores de relações de sentido (tempo, causa, oposição, conclusão, comparação), com nível adequado de informatividade.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('b4971fd1-2034-41b3-9d09-aed13a59c9d3'::uuid,'EF05LP28','Observar, em ciberpoemas e minicontos infantis em mídia digital, os recursos multissemióticos presentes nesses textos digitais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('728883a3-4e7f-4f5d-8869-60c6fb14c15c'::uuid,'5L1.1','Identificar a ideia central do texto.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('3a3765ac-d6bc-466c-8524-ad9a06650abb'::uuid,'5L1.2','Localizar informação explícita.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b7c39199-f2a7-4a9e-94ab-dc66057ef6e7'::uuid,'5L1.3','Reconhecer diferentes gêneros textuais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('aef50b8a-9915-465b-b11c-b0c6c974647c'::uuid,'5L1.4','Identificar elementos constitutivos de textos narrativos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('ef3d5408-11f3-4d72-82e9-6406fcbcff47'::uuid,'5L1.5','Reconhecer diferentes modos de organização composicional de textos em versos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('4ff1afed-0039-41ff-93ee-ce63bc176109'::uuid,'5L1.6','Identificar as marcas de organização de textos dramáticos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e2de6f59-c03f-4e7b-84c3-c54f3acf68c9'::uuid,'5L2.1','Analisar elementos constitutivos de gêneros textuais diversos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('901c9dbb-3bd6-461f-a300-3b9c77a3ce74'::uuid,'5L2.2','Analisar relações de causa e consequência.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('db705c31-c3ca-4b40-8a6f-98cfa3de4b09'::uuid,'5L2.3','Analisar o uso de recursos de persuasão em textos verbais e/ ou multimodais.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('a3261639-5583-48ec-ab0e-02283d0f3b58'::uuid,'5L2.4','Distinguir fatos de opiniões em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('dd84f75c-51c8-40af-bb83-1866877e2ba5'::uuid,'5L2.5','Analisar informações apresentadas em gráficos, infográficos ou tabelas.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('58548fdb-8ff0-4995-a427-b6c6da49711e'::uuid,'5L2.6','Inferir informações implícitas em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('e9c14ee0-c2ca-4405-a40e-0c28e13d9eb3'::uuid,'5L2.7','Inferir o sentido de palavras ou expressões em textos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('921b9cec-8d38-40bd-b65a-424848fe05f8'::uuid,'5L2.8','Analisar os efeitos de sentido de recursos multissemióticos em textos que circulam em diferentes suportes.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('c769afc7-8083-4be0-b947-ed997d085843'::uuid,'5L2.9','Analisar a construção de sentidos de textos em versos com base em seus elementos constitutivos.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('631546b3-f772-46a5-b3f9-f7772ab3a097'::uuid,'5L3.1','Avaliar a fidedignidade de informações sobre um mesmo fato veiculadas em diferentes mídias.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('b727596e-6de7-4d38-9b4b-78b6c1c7df8e'::uuid,'5A1.1','Reconhecer os usos da pontuação.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('da8ff008-2981-485d-a858-383f52593c4b'::uuid,'5A1.2','Reconhecer em textos o significado de palavras derivadas a partir de seus afixos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
INSERT INTO public.skills (id,code,description,subject_id,grade_id) VALUES
	 ('3a77cbc3-0eb6-4d7f-8615-92334fa515bc'::uuid,'5A1.3','Identificar as variedades linguísticas em textos.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('5555058d-95d9-4876-a7c5-f11b9bdca323'::uuid,'5A1.4','Identificar os mecanismos de progressão textual.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid),
	 ('4f0457af-bb1a-4bec-a0f0-7c6041fec091'::uuid,'5A1.5','Identificar os mecanismos de referenciação lexical e pronominal.','4d29b4f1-7bd7-42c0-84d5-111dc7025b90',NULL),
	 ('cccc4b4d-da10-4597-bb76-394ea0eb7ba6'::uuid,'5A2.1','Analisar os efeitos de sentido decorrentes do uso da pontuação.','44f3421e-ca84-4fe5-a449-a3d9bfa3db3d','f5688bb2-9624-487f-ab1f-40b191c96b76'::uuid);
